import sys
# [Fix] Force UTF-8 encoding for standard streams
# This prevents UnicodeEncodeError on Windows when printing emojis or special characters.
try:
    if sys.stdout.encoding != 'utf-8':
        sys.stdout = open(sys.stdout.fileno(), mode='w', encoding='utf-8', buffering=1)
    if sys.stderr.encoding != 'utf-8':
        sys.stderr = open(sys.stderr.fileno(), mode='w', encoding='utf-8', buffering=1)
except Exception as e:
    # Handle cases where sys.stdout.fileno() might not be available (e.g., some IDEs)
    # or if the stream is already closed.
    # Using original sys.stderr for this message to ensure it gets printed
    original_stderr = sys.__stderr__ if hasattr(sys, '__stderr__') else sys.stderr
    print(f"⚠️ [System] Failed to re-encode standard streams to UTF-8: {e}", file=original_stderr)
    print("         This may lead to display issues with Unicode characters.", file=original_stderr)

