# [Qt WebEngine] GPU/렌더링 스택 안정화
# Why: Windows DWM IDCompositionDevice4 QueryInterface 실패(0x80004002) + GLES3
# 컨텍스트 생성 실패(kFatalFailure) → loadFinished 누락. QWebEngineView import
# 이전에 세팅돼야 Chromium 런처에 전달됨.
# Note: --in-process-gpu 는 --disable-gpu 와 모순(GPU 자체가 꺼졌는데 in-process
# 로 올리는 의미 없음)이라 제거. 필요하면 EIDOS_WEBENGINE_INPROCESS_GPU=1 로 복원.
_webengine_flags = [
    "--disable-gpu",
    "--disable-gpu-compositing",
    "--use-gl=disabled",
    "--disable-software-rasterizer",
    "--log-level=2",
    "--disable-features=UseOzonePlatform,VizDisplayCompositor",
]
if os.environ.get("EIDOS_WEBENGINE_INPROCESS_GPU") == "1":
    _webengine_flags.append("--in-process-gpu")
os.environ["QTWEBENGINE_CHROMIUM_FLAGS"] = " ".join(_webengine_flags)
