def load_connectors() -> list:
    """커넥터 설정 로드. 파일 없으면 기본값 반환."""
    if os.path.exists(CONNECTORS_FILE):
        try:
            with open(CONNECTORS_FILE, 'r', encoding='utf-8') as f:
                saved = json.load(f)
            # 기본 커넥터 구조 유지하면서 저장된 값 병합
            merged = []
            saved_map = {c["id"]: c for c in saved}
            for default in DEFAULT_CONNECTORS:
                c = dict(default)
                if c["id"] in saved_map:
                    s = saved_map[c["id"]]
                    c["enabled"] = s.get("enabled", False)
                    c["icon_path"] = s.get("icon_path", "")  # ← icon_path 복원
                    saved_fields = {f["key"]: f["value"] for f in s.get("fields", [])}
                    for field in c["fields"]:
                        field["value"] = saved_fields.get(field["key"], "")
                merged.append(c)
            # 사용자 정의 커넥터 (id가 DEFAULT에 없는 것) 추가
            default_ids = {c["id"] for c in DEFAULT_CONNECTORS}
            for c in saved:
                if c["id"] not in default_ids:
                    merged.append(c)
            return merged
        except Exception:
            pass
    return [dict(c) for c in DEFAULT_CONNECTORS]

def save_connectors(connectors: list):
    """커넥터 설정 저장."""
    os.makedirs(os.path.dirname(CONNECTORS_FILE), exist_ok=True)
    try:
        with open(CONNECTORS_FILE, 'w', encoding='utf-8') as f:
            json.dump(connectors, f, indent=2, ensure_ascii=False)
    except Exception as e:
        print(f"❌ 커넥터 저장 실패: {e}")
app_settings = load_settings()
set_language(app_settings["language"]) # 프로그램 시작 시 언어 설정 적용

