# 7. 테마 설정 로드 함수
def load_theme_setting() -> str:
    """ eidos_settings.json에서 테마 설정을 불러옵니다. """
    try:
        if os.path.exists(SETTINGS_FILE):
            with open(SETTINGS_FILE, 'r', encoding='utf-8') as f:
                settings = json.load(f)
                return settings.get("theme", "Modern Dark")
    except Exception as e:
        print(f"⚠️ [{tr('log_theme_load_fail')}]: {e}")
    return "Modern Dark" # 기본값

# 8. 테마 설정 저장 함수
def save_theme_setting(theme_name: str):
    """ eidos_settings.json에 테마 설정을 저장합니다. """
    settings = {}
    try:
        if os.path.exists(SETTINGS_FILE):
            with open(SETTINGS_FILE, 'r', encoding='utf-8') as f:
                settings = json.load(f)
    except Exception:
        pass

    try:
        settings["theme"] = theme_name
        with open(SETTINGS_FILE, 'w', encoding='utf-8') as f:
            json.dump(settings, f, indent=4)
    except Exception as e:
        print(f"❌ [{tr('log_theme_save_fail')}]: {e}")

