class FileWorker(QThread):
    finished_signal = Signal(bool, str, str) # success, message, content(read only)

    def __init__(self, mode, path, content=None):
        super().__init__()
        self.mode = mode # 'read' or 'write'
        self.path = path
        self.content = content

    def run(self):
        try:
            if self.mode == 'write':
                with open(self.path, 'w', encoding='utf-8-sig') as f:
                    f.write(self.content)
                self.finished_signal.emit(True, "저장 완료", "")
            elif self.mode == 'read':
                with open(self.path, 'r', encoding='utf-8') as f:
                    data = f.read()
                self.finished_signal.emit(True, "읽기 완료", data)
        except Exception as e:
            logger.error(f"File I/O Error ({self.mode}): {e}")
            self.finished_signal.emit(False, str(e), "")

class TerminalWidget(QTextEdit):
    """ 
    [Console] 테마에 따라 색상이 반응하는 스마트 터미널 위젯 
    """
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setReadOnly(True)
        self.setFont(QFont("Consolas", 10))
        
        # 기본 색상 (초기화용)
        self.stdout_col = QColor("#CCCCCC")
        self.stderr_col = QColor("#FF5555")
        self.system_col = QColor("#4CAF50")
        
        # 초기 스타일 — set_theme()이 나중에 덮어쓰므로 ObjectName만 세팅 (기본 테마 배경 사용)
        self.setObjectName("TerminalOutput")

    def set_theme(self, theme_name: str):
        """ 테마 이름에 맞춰 터미널의 배경색과 글자색을 동적으로 변경합니다. """
        # 새로운 THEMES 딕셔너리에서 테마 객체를 가져옵니다.
        theme_obj = THEMES.get(theme_name, MODERN_DARK_THEME)
        c = theme_obj["colors"]

        # 1. 배경색 및 기본 글자색 설정
        bg_col = c.get("bg_input", "#1E1E1E")
        text_col = c.get("text_primary", "#CCCCCC")
        border_col = c.get("border_subtle", "#333333")
        
        self.setStyleSheet(f"""
            QTextEdit {{
                background-color: {bg_col};
                color: {text_col};
                border: 1px solid {border_col};
                border-radius: 4px;
                padding: 5px;
                font-family: 'Consolas', monospace;
            }}
        """)
        
        # 2. 텍스트 출력 색상(Stdout/Stderr) 결정
        is_dark = theme_obj.get("is_dark", True)
        
        if is_dark:
            self.stdout_col = QColor("#E0E0E0") # 밝은 회색
            self.stderr_col = QColor("#FF6B6B") # 밝은 빨강 (가독성 UP)
            self.system_col = QColor("#69F0AE") # 형광 초록
        else:
            self.stdout_col = QColor("#333333") # 진한 회색
            self.stderr_col = QColor("#D32F2F") # 진한 빨강
            self.system_col = QColor("#2E7D32") # 진한 초록

    def write_output(self, text):
        """ 일반 출력 (STDOUT) """
        self.moveCursor(QTextCursor.End)
        self.setTextColor(self.stdout_col) # 동적 색상 사용
        self.insertPlainText(text)
        self.verticalScrollBar().setValue(self.verticalScrollBar().maximum())

    def write_error(self, text):
        """ 에러 출력 (STDERR) """
        self.moveCursor(QTextCursor.End)
        self.setTextColor(self.stderr_col) # 동적 색상 사용
        self.insertPlainText(text)
        self.verticalScrollBar().setValue(self.verticalScrollBar().maximum())

    def write_system(self, text):
        """ 시스템 메시지 """
        self.moveCursor(QTextCursor.End)
        self.setTextColor(self.system_col) # 동적 색상 사용
        self.insertPlainText(f"\n[SYSTEM] {text}\n")
        self.verticalScrollBar().setValue(self.verticalScrollBar().maximum())

    def append(self, text):
        """ [Fix] 기존 코드(debug_console)와의 호환성을 위한 래퍼 메서드 """
        self.write_system(text)

    def clear_terminal(self):
        self.clear()

