# 📝 UI 컴포넌트: 줄 번호 영역 (Line Number Area)
# ----------------------------------------------------------------------

# 9. 줄 번호 표시 위젯 클래스
class LineNumberArea(QWidget):
    """ 
    QTextEdit 또는 QPlainTextEdit의 왼쪽에 줄 번호를 표시하는 위젯입니다.
    테마 변경 시 update()를 통해 색상이 자동 반영되도록 QPalette를 활용합니다.
    """
    def __init__(self, editor: QTextEdit):
        super().__init__(editor)
        self.editor = editor
        # 배경색 자동 채움을 끄고 paintEvent에서 직접 제어 (투명도 문제 방지)
        self.setAutoFillBackground(True)

    def sizeHint(self) -> QSize:
        """ 위젯의 권장 크기 반환 (너비 계산) """
        return QSize(self.calculate_width(), 0)

    def calculate_width(self) -> int:
        """ 
        현재 문서의 줄 수(Block Count)에 따라 필요한 너비를 계산합니다. 
        """
        block_count = self.editor.document().blockCount()
        # 최소 3자리(100단위) 공간 확보
        digits = len(str(max(1, block_count)))
        digits = max(3, digits) 
        
        # '9' 글자의 너비를 기준으로 계산 + 여백(15px)
        font_metrics = self.editor.fontMetrics()
        space = 15 + font_metrics.horizontalAdvance('9') * digits
        return space

    def paintEvent(self, event: QPaintEvent):
        """ 
        줄 번호를 실제로 그리는 함수. 
        QTextEdit의 뷰포트와 동기화하여 현재 보이는 영역만 그립니다.
        """
        painter = QPainter(self)
        try:
            # 1. 테마 색상 가져오기 (현재 테마의 Palette 사용)
            palette = self.palette()
            bg_color = palette.color(QPalette.ColorRole.AlternateBase)
            text_color = palette.color(QPalette.ColorRole.Text)
            
            # 배경 그리기
            painter.fillRect(event.rect(), bg_color)

            # 2. 편집기의 폰트 설정 가져오기
            font = self.editor.font()
            painter.setFont(font)
            painter.setPen(text_color)

            # 3. 현재 보이는 첫 번째 블록(줄) 찾기
            block = self.editor.firstVisibleBlock()
            block_number = block.blockNumber()
            
            # 블록의 상단 위치 계산 (Y 좌표)
            top = self.editor.blockBoundingGeometry(block).translated(self.editor.contentOffset()).top()
            bottom = top + self.editor.blockBoundingRect(block).height()
            
            # 높이(폰트 높이) 캐싱
            font_height = self.editor.fontMetrics().height()
            area_width = self.width()

            # 4. 화면에 보이는 영역만큼 반복해서 그리기
            while block.isValid() and top <= event.rect().bottom():
                if block.isVisible() and bottom >= event.rect().top():
                    number = str(block_number + 1)
                    
                    # 텍스트 그리기 (우측 정렬, 우측 여백 5px)
                    painter.drawText(
                        0, 
                        int(top), 
                        area_width - 5, 
                        font_height,
                        Qt.AlignmentFlag.AlignRight, 
                        number
                    )

                # 다음 블록으로 이동
                block = block.next()
                top = bottom
                bottom = top + self.editor.blockBoundingRect(block).height()
                block_number += 1
        finally:
            painter.end()

# 10. 도움말 다이얼로그 클래스 (2026-06-06 갱신)
#   - QTabWidget 5 탭 (시작하기 / 기본 사용법 / AIRA / 자율 개발 / 명령어 전체)
#   - '명령어 전체' 탭은 ChatWindow._SLASH_COMMANDS 에서 *동적* 생성 → 명령 추가 시 자동 반영
#     (옛 '텔레그램 15개 하드코딩 표' 는 제거됨 — 단일 출처는 _SLASH_COMMANDS)
class HelpDialog(QDialog):
    """ EIDOS 사용법 + 슬래시 명령어 도움말 (탭 5개)"""

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setWindowTitle("EIDOS 도움말")
        self.resize(880, 680)

        main_layout = QVBoxLayout(self)
        main_layout.setContentsMargins(10, 10, 10, 10)

        # ── 헤더 ─────────────────────────────────────────────
        header = QLabel(
            "<h2 style='color:#6A0DAD; margin:0;'>📘 EIDOS 사용 가이드</h2>"
            "<p style='color:#666; margin-top:4px;'>"
            "탭을 선택해 영역별 사용법을 확인하세요."
            "</p>"
        )
        header.setTextFormat(Qt.TextFormat.RichText)
        main_layout.addWidget(header)

        # ── 탭 ───────────────────────────────────────────────
        self.tabs = QTabWidget()
        self.tabs.setStyleSheet("""
            QTabBar::tab {
                min-width: 110px;
                padding: 8px 18px;
                font-size: 10pt;
            }
            QTabBar::tab:selected {
                font-weight: bold;
                color: #6A0DAD;
            }
        """)

        self.tabs.addTab(self._make_browser(self._html_intro()), "🚀 시작하기")
        self.tabs.addTab(self._make_browser(self._html_basic_usage()), "💬 기본 사용법")
        self.tabs.addTab(self._make_browser(self._html_aira()), "🎀 AIRA 기능")
        self.tabs.addTab(self._make_browser(self._html_dev()), "🛠 자율 개발")
        self.tabs.addTab(self._make_browser(self._html_commands()), "⌨️ 명령어 전체")

        main_layout.addWidget(self.tabs)

        # ── 하단 닫기 버튼 ──────────────────────────────────
        btn_layout = QHBoxLayout()
        btn_layout.addStretch()
        close_btn = QPushButton("닫기")
        close_btn.setFixedSize(100, 36)
        close_btn.clicked.connect(self.accept)
        close_btn.setStyleSheet("""
            QPushButton {
                background-color: #E0E0E0;
                border: 1px solid #CCC;
                border-radius: 5px;
                font-size: 10pt;
            }
            QPushButton:hover { background-color: #D0D0D0; }
        """)
        btn_layout.addWidget(close_btn)
        main_layout.addLayout(btn_layout)

    # ── 탭 빌더 헬퍼 ─────────────────────────────────────
    def _make_browser(self, html: str) -> QTextBrowser:
        tb = QTextBrowser()
        tb.setOpenExternalLinks(True)
        tb.setStyleSheet("""
            QTextBrowser {
                background-color: #ffffff;
                color: #333;
                padding: 18px;
                font-family: "Segoe UI", "Malgun Gothic", sans-serif;
                font-size: 10.5pt;
                border: 1px solid #ddd;
                border-radius: 6px;
            }
        """)
        tb.setHtml(html)
        return tb

    # ── 탭 1: 시작하기 ────────────────────────────────────
