        self._settings_gcal_sync_btn.setStyleSheet("""
            QPushButton {
                background: #1e3a5f; color: #93C5FD;
                border: 1px solid #1e40af; border-radius: 6px;
                padding: 5px 14px; font-weight: bold; font-size: 9pt;
            }
            QPushButton:hover { background: #1e40af; color: white; }
        """)
        self._settings_gcal_sync_btn.setToolTip(tr("tooltip_gcal_btn"))
