# ══════════════════════════════════════════════════════════════════════
# [.auto 자율 실행 편집기 2026-05-24]
# 사용자 결정 — 메인 채팅창 wire 누락 디버깅 9번째 실패 후 완전 격리 경로.
# 코드/문서 편집기의 자매 — `.auto` 확장자·QMainWindow 자체 창·ChatWindow 와 0 결합.
# 자체 input·자체 worker 호출·결과 카드는 자체 panel.
# ══════════════════════════════════════════════════════════════════════

AUTO_FILE_EXT = ".auto"
AUTO_FILE_FILTER = "EIDOS 자율 실행 task (*.auto);;모든 파일 (*.*)"


def load_auto_file(path: str) -> dict:
    """.auto 파일 → dict. 실패 시 빈 dict graceful."""
    try:
        if not path or not os.path.exists(path):
            return {}
        with open(path, "r", encoding="utf-8") as f:
            _data = json.load(f) or {}
        if not isinstance(_data, dict):
            return {}
        return _data
    except Exception as _e:
        print(f"  [AutoFile] load 실패: {_e}")
        return {}


def save_auto_file(path: str, data: dict) -> bool:
    """dict → .auto 파일 (JSON·atomic write·ensure_ascii=False·indent=2)."""
    try:
        if not path:
            return False
        if not path.lower().endswith(AUTO_FILE_EXT):
            path = path + AUTO_FILE_EXT
        os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
        import datetime as _dt_af
        # updated_at 자동 갱신
        _data = dict(data or {})
        _data["updated_at"] = _dt_af.datetime.now().isoformat(timespec="seconds")
        if "created_at" not in _data:
            _data["created_at"] = _data["updated_at"]
        _tmp = path + ".tmp"
        with open(_tmp, "w", encoding="utf-8") as f:
            json.dump(_data, f, ensure_ascii=False, indent=2)
        os.replace(_tmp, path)
        return True
    except Exception as _e:
        print(f"  [AutoFile] save 실패: {_e}")
        return False


def make_empty_auto_task() -> dict:
    """신규 .auto task 기본 구조."""
    import datetime as _dt_em
    _now = _dt_em.datetime.now().isoformat(timespec="seconds")
    return {
        "topic": "",
        "domain": "",
        "user_text": "",
        "context_facts": {},
        "questions": [],
        "plan": None,
        "attempts": [],
        "status": "draft",  # draft | clarifying | planning | active | completed | failed
        "created_at": _now,
        "updated_at": _now,
        "version": 1,
    }


class AutonomousEditor(QMainWindow):
    """[.auto 자율 실행 편집기 2026-05-24] 코드/문서 편집기 자매·완전 격리.

    구조:
      - 상단: topic 입력 + 도메인 select + ▶️ 실행 버튼
      - 중간 좌: 역질문 Q&A 영역
      - 중간 우: plan 카드 영역
      - 하단: attempts 로그
      - 파일 메뉴: 새 task·열기·저장·다른 이름으로

    실행 흐름:
      - 실행 버튼 → topic + context_facts → chat_window._eidos_assess_context_async
        → questions 받으면 Q&A 영역에 표시·답변 받으면 _eidos_plan_autonomous_async
        → plan 받으면 plan 카드 영역에 표시·✅ 진행 → workflow worker 또는 chain 분기
      - 모든 결과는 *자체 panel* 에 표시 (chat_window 안 거침)
      - thread-safe signal queued connection (worker thread → main thread).
    """

    # thread-safe append signals (worker → main thread queued)
    _signal_set_status = Signal(str, str)  # (status_str, color_hex)
    _signal_append_log = Signal(str)
    _signal_set_questions = Signal(list)   # list[str]
    _signal_set_plan = Signal(dict)        # plan dict

    def __init__(self, parent=None, worker=None, chat_window=None,
                 initial_path: str = ""):
        super().__init__(parent)
        self.setWindowTitle("🎯 자율 실행 편집기 (.auto)")
        self.resize(1100, 720)
        self._worker = worker
        self._chat_window = chat_window
        self._current_path = initial_path or ""
        self._task: dict = make_empty_auto_task()
        self._dirty = False

        # signal queued connect (thread-safe)
        try:
            self._signal_set_status.connect(
                self._on_set_status, Qt.ConnectionType.QueuedConnection
            )
            self._signal_append_log.connect(
                self._on_append_log, Qt.ConnectionType.QueuedConnection
            )
            self._signal_set_questions.connect(
                self._on_set_questions, Qt.ConnectionType.QueuedConnection
            )
            self._signal_set_plan.connect(
                self._on_set_plan, Qt.ConnectionType.QueuedConnection
            )
        except Exception as _e_sig:
            print(f"  [AutoEditor] signal connect 실패 (graceful): {_e_sig}")

        self._setup_ui()
        self._setup_menu()
        self._apply_pure_black_style()
        if initial_path:
            self._load_from_path(initial_path)

    def _apply_pure_black_style(self):
        # 사용자 요청 (2026-05-24): 전역 Modern Dark 의 회색 surface(#27272a)
        # 새는 거 차단·이 창만 순검정. 메인/플래너 등 다른 창은 영향 X.
        self.setStyleSheet("""
            QMainWindow, QWidget, QFrame, QSplitter { background-color: #000000; color: #e5e7eb; }
            QTextEdit, QPlainTextEdit, QLineEdit, QComboBox, QListWidget, QTreeWidget {
                background-color: #000000; color: #e5e7eb;
                border: 1px solid #1f1f1f; border-radius: 4px; padding: 4px;
                selection-background-color: #2a2a2a;
            }
            QTextEdit:focus, QPlainTextEdit:focus, QLineEdit:focus, QComboBox:focus {
                border: 1px solid #3a3a3a;
            }
            QComboBox QAbstractItemView {
                background-color: #000000; color: #e5e7eb;
                selection-background-color: #1a1a1a;
            }
            QPushButton {
                background-color: #000000; color: #e5e7eb;
                border: 1px solid #2a2a2a; border-radius: 4px; padding: 4px 12px;
            }
            QPushButton:hover { background-color: #111111; border-color: #3a3a3a; }
            QPushButton:disabled { background-color: #000000; color: #4a4a4a; border-color: #1a1a1a; }
            QLabel { background-color: transparent; color: #e5e7eb; }
            QMenuBar { background-color: #000000; color: #e5e7eb; }
            QMenuBar::item { background-color: #000000; padding: 4px 10px; }
            QMenuBar::item:selected { background-color: #1a1a1a; }
            QMenu { background-color: #000000; color: #e5e7eb; border: 1px solid #2a2a2a; }
            QMenu::item:selected { background-color: #1a1a1a; }
            QSplitter::handle { background-color: #000000; }
            QSplitter::handle:hover { background-color: #1a1a1a; }
            QScrollBar:vertical, QScrollBar:horizontal { background-color: #000000; border: none; }
            QScrollBar::handle { background-color: #2a2a2a; border-radius: 4px; }
            QScrollBar::handle:hover { background-color: #3a3a3a; }
            QScrollBar::add-line, QScrollBar::sub-line { background: none; border: none; }
        """)
        # 실행 버튼은 별도 녹색 stylesheet (per-widget override 유지) — 영향 X

    def _setup_ui(self):
        central = QWidget(self)
