class DocumentEditorWindow(QWidget):
    """ EIDOS 보고서/문서 생성을 위한 전용 편집 창 """

    def __init__(
        self,
        parent=None,
        project_dir: str = "eidos_files/default_doc_project",
        initial_file: Optional[str] = None,
        eidos_worker=None,
        chat_history_deque=None,
    ):
        super().__init__(parent)

        # --------------------------------------------------
        # 1. 기본 상태 / 의존성 초기화
        # --------------------------------------------------
        self.project_root = os.path.abspath(project_dir)
        self.setWindowTitle(
            tr("doc_title").format(dir=os.path.basename(project_dir))
        )
        self.setGeometry(250, 250, 1200, 800)

        self.current_file_path: Optional[str] = None
        self.eidos_worker = eidos_worker
        self.worker = eidos_worker
        self.doc_before_ai_modification: Optional[str] = None
        self.chat_history_deque = (
            chat_history_deque if chat_history_deque else deque(maxlen=30)
        )

        # 내부 상태
        self._is_syncing_to_core = False
        self.is_dirty = False # 자동 저장을 위한 Dirty Flag
        
        # [백링크/네비게이션] 히스토리 관리
        self.navigation_history: list[str] = []
        self.navigation_forward_stack: list[str] = []
        self._is_navigating: bool = False # 네비게이션 중복 추가 방지 플래그

        # 캐릭터 관련 속성 (초기값만 선언)

        # --------------------------------------------------
        # 2. UI 생성
        # --------------------------------------------------
        self._init_ui()

        # --------------------------------------------------
        # 4. 시그널 연결 (Ctrl+S/F/G 등 단축키도 _setup_signals 에서 처리)
        # --------------------------------------------------
        self._setup_signals()

        if self.worker:
            try:
                self.worker.modification_suggestion_ready.connect(
                    self._on_proposal_received
                )
            except Exception as e:
                print(f"[DocumentEditorWindow] Signal connection error: {e}")

        # --------------------------------------------------
        # 5. 초기화 작업
        # --------------------------------------------------
        self._refresh_file_tree()
        self._start_autosave()
        self._load_qa_list()
        self._scan_for_backlinks() # 초기 백링크 맵 생성

        if initial_file:
            self._open_file_in_editor(file_path=initial_file)

    def _wrap_with_header(self, title: str, content_widget):
        """[Phase UI 2026-05-03] 패널 wrapper — 섹션 헤더 + 본문.

        좌/우 패널을 감싸 visual 구획 명확화 + 헤더 라벨로 사용자에게 영역 안내.

        [P3-1 2026-05-11] QGraphicsDropShadowEffect 적용 — 패널이 떠 있는 카드 인상.
        """
        from PySide6.QtWidgets import QFrame
        wrap = QFrame()
        wrap.setObjectName("EditorPanel")
        lay = QVBoxLayout(wrap)
        lay.setContentsMargins(0, 0, 0, 0)
        lay.setSpacing(0)
        header = QLabel(title)
        header.setObjectName("EditorPanelHeader")
        header.setMinimumHeight(28)
        lay.addWidget(header)
        lay.addWidget(content_widget, 1)
        # 카드 elevation — blur 16, offset (0, 2), 약한 검은 그림자
        try:
            shadow = QGraphicsDropShadowEffect(wrap)
            shadow.setBlurRadius(16)
            shadow.setOffset(0, 2)
            shadow.setColor(QColor(0, 0, 0, 90))  # alpha 90/255 ≈ 35%
            wrap.setGraphicsEffect(shadow)
        except Exception as _e:
            print(f"[DocumentEditorWindow] panel shadow failed: {_e}")
        return wrap

    def _init_ui(self):
        """UI 구성요소 초기화 (강의 모드 + QA + AI Diff Viewer 통합)"""
        layout = QVBoxLayout(self)
        self.main_splitter = QSplitter(Qt.Horizontal)

        # 미리보기 관련 속성 사전 초기화 (참조 전 반드시 존재해야 함)
        self.html_preview = None
        self.preview_update_timer = QTimer(self)
        self.preview_update_timer.setSingleShot(True)
        self.preview_update_timer.setInterval(500)

    # -----------------------------
    # 강의 모드 상태
    # -----------------------------
        self.qa_queue = []

    # -----------------------------
    # 좌측: 파일 트리
    # -----------------------------
        self.file_tree = QTreeWidget(self)
        self.file_tree.setHeaderLabels([tr("header_toc")])
        self.file_tree.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)

    # -----------------------------
    # 중앙 스택
    # -----------------------------
        self.central_stack = QStackedWidget()

    # ===== [중앙 화면 1] 문서 에디터 =====
        editor_view_widget = QWidget()
        editor_view_layout = QVBoxLayout(editor_view_widget)
        editor_view_layout.setContentsMargins(0, 0, 0, 0)

        editor_console_splitter = QSplitter(Qt.Vertical)
        editor_widget = QWidget()
        editor_layout = QVBoxLayout(editor_widget)
        editor_layout.setContentsMargins(0, 0, 0, 0)
        editor_layout.setSpacing(0)

        self._setup_toolbar(editor_layout)

        self.doc_editor = WikiLinkTextEdit(self)
        self.doc_editor.setFont(QFont("Malgun Gothic", 11))
        # [P0-2 2026-05-11] 문서 본문 구조 강조 — heading/bullet/link 다색화
        # [P1-1 2026-05-11] documentMargin 16px — 텍스트가 패널 경계에 붙지 않게
        # [P3-2 2026-05-11] 현재 테마 colors 주입 → 헤딩 H1~H3 가 accent 추적
        try:
            self.doc_editor.document().setDocumentMargin(16)
            _theme_colors = self._current_theme_colors()
            self.doc_highlighter = MarkdownStructureHighlighter(
                self.doc_editor.document(), theme_colors=_theme_colors,
            )
        except Exception as _e:
            print(f"[DocumentEditorWindow] highlighter attach failed: {_e}")
        editor_layout.addWidget(self.doc_editor)

        # [P0-1 2026-05-11] debug_console 시각 분리 — 본문에 섞이는 인상 제거
        #   (1) 헤더 라벨 + 별도 frame 으로 본문과 구획
        #   (2) 9pt monospace + 다른 배경색 (QSS) 으로 본문 텍스트와 톤 차별
        #   (3) 우측 상단 "지우기" 버튼으로 누적 로그 정리 가능
        self.debug_console = QTextEdit(self)
        self.debug_console.setObjectName("DebugConsole")
        self.debug_console.setReadOnly(True)
        self.debug_console.setMaximumHeight(150)
        self.debug_console.setFont(QFont("Consolas", 9))

        console_frame = QFrame()
        console_frame.setObjectName("DebugConsoleFrame")
        # [P0-1 v2 2026-05-11] 콘솔이 splitter 에서 50% 차지하던 문제 — wrap 자체에 maxHeight 캡
