def _resolve_doc_palette(theme_colors: dict | None) -> dict[str, str]:
    """[P3-2 2026-05-11] 테마 colors dict → MarkdownStructureHighlighter 용 palette.

    None / 이상 입력 시 dark default fallback. is_dark 판정은 호출자가 theme dict 의
    is_dark 플래그로 결정 → 여기선 colors dict 만 받고 accent 만 override.
    """
    if not theme_colors:
        return dict(_DEFAULT_DOC_PALETTE_DARK)
    # is_dark 휴리스틱: bg_base 어두우면 dark
    bg = theme_colors.get("bg_base", "#000000")
    is_dark = True
    try:
        # #RRGGBB → 평균 luminance 추정
        h = bg.lstrip("#")
        if len(h) == 6:
            r, g, b = int(h[0:2], 16), int(h[2:4], 16), int(h[4:6], 16)
            is_dark = (r + g + b) / 3 < 128
    except Exception:
        pass
    base = dict(_DEFAULT_DOC_PALETTE_DARK if is_dark else _DEFAULT_DOC_PALETTE_LIGHT)
    # 헤딩 H1~H3 는 theme accent 따라가게 — 브랜드 일치
    accent = theme_colors.get("accent_primary")
    accent_hover = theme_colors.get("accent_hover")
    accent_pressed = theme_colors.get("accent_pressed")
    if accent:
        base["heading_h1"] = accent_hover or accent
        base["heading_h2"] = accent
        base["heading_h3"] = accent_pressed or accent
    return base


class MarkdownStructureHighlighter(QSyntaxHighlighter):
    """[P0-2 2026-05-11] .txt/.md 본문 구조 강조.

    plain text 에디터를 단색에서 multi-tone 으로 끌어올리는 경량 하이라이터.
    헤딩/리스트 항목/위키링크/코드/숫자/구분선 7개 패턴을 색·굵기·정렬로 분리.

    PythonHighlighter (코드 편집기 전용) 와 동거 — 이 클래스는 문서 편집기 doc_editor 에 attach.

    [P3-2 2026-05-11] palette 주입 가능 — `_resolve_doc_palette(theme_colors)` 로 빌드해서
    set_palette() 로 교체 가능 + 자동 rehighlight. 헤딩 H1~H3 는 theme accent 추적.
    """

    def __init__(self, document, theme_colors: dict | None = None):
        super().__init__(document)
        self.rules: list[tuple[QRegularExpression, QTextCharFormat]] = []
        # [P1-1 2026-05-11] 헤딩 라인 식별용 — block 단위 spacing/line-height 적용
        self.heading_patterns: list[QRegularExpression] = []
        self.palette: dict[str, str] = _resolve_doc_palette(theme_colors)
        self._build_rules()

    def set_palette(self, theme_colors: dict | None) -> None:
        """[P3-2] 테마 변경 시 호출 — palette 재계산 + 규칙 재빌드 + rehighlight."""
        self.palette = _resolve_doc_palette(theme_colors)
        self.rules.clear()
        self.heading_patterns.clear()
        self._build_rules()
        self.rehighlight()

    def _build_rules(self) -> None:
        """rules + heading_patterns 빌드. palette 변경 시 재호출 가능."""
        p = self.palette

        def _add_heading(pattern_str: str, color_key: str, size: int = 0,
                         opts=QRegularExpression.NoPatternOption):
            fmt = QTextCharFormat()
            fmt.setForeground(QColor(p[color_key]))
            fmt.setFontWeight(QFont.Bold)
            if size:
                fmt.setFontPointSize(size)
            pat = QRegularExpression(pattern_str, opts)
            self.rules.append((pat, fmt))
            self.heading_patterns.append(pat)

        # ATX 헤딩 (#, ##, ###~######) — theme accent 추적
        _add_heading(r"^#\s+.*$",       "heading_h1", 14)
        _add_heading(r"^##\s+.*$",      "heading_h2", 13)
        _add_heading(r"^#{3,6}\s+.*$",  "heading_h3", 12)
        # Part / Chapter / 챕터 / 제N장
        _add_heading(
            r"^(Part|Chapter|챕터|제\s*\d+장)\s*\d*[\.\s].*$",
            "heading_part", 14,
            QRegularExpression.CaseInsensitiveOption,
        )
        # N-N. 또는 N-N-N. 서브헤딩
        _add_heading(r"^\d+(-\d+){1,3}\.\s+.*$", "heading_sub", 0)

        # 불릿 마커 자체 (•, -, *)
        bullet = QTextCharFormat()
        bullet.setForeground(QColor(p["bullet"]))
        bullet.setFontWeight(QFont.Bold)
        self.rules.append((QRegularExpression(r"^\s*[•\-\*]\s"), bullet))

        # 숫자 리스트 마커 (1. 2) 등)
        num_marker = QTextCharFormat()
        num_marker.setForeground(QColor(p["num_marker"]))
        num_marker.setFontWeight(QFont.Bold)
        self.rules.append((QRegularExpression(r"^\s*\d+[\.\)]\s"), num_marker))

        # 위키링크 [[파일명]]
        wiki = QTextCharFormat()
        wiki.setForeground(QColor(p["wiki_link"]))
        wiki.setFontUnderline(True)
        self.rules.append((QRegularExpression(r"\[\[[^\]]+\]\]"), wiki))

        # 일반 markdown 링크 [text](url)
        link = QTextCharFormat()
        link.setForeground(QColor(p["md_link"]))
        link.setFontUnderline(True)
        self.rules.append((QRegularExpression(r"\[[^\]]+\]\([^\)]+\)"), link))

        # 인라인 코드 `code`
        code = QTextCharFormat()
        code.setForeground(QColor(p["code"]))
        code.setFontFamily("Consolas")
        self.rules.append((QRegularExpression(r"`[^`]+`"), code))

        # 굵은 글씨 **text**
        bold = QTextCharFormat()
        bold.setFontWeight(QFont.Bold)
        bold.setForeground(QColor(p["bold"]))
        self.rules.append((QRegularExpression(r"\*\*[^\*]+\*\*"), bold))

        # 기울임 *text* (위 **bold** 와 충돌 회피 위해 단일 *)
        italic = QTextCharFormat()
        italic.setFontItalic(True)
        italic.setForeground(QColor(p["italic"]))
        self.rules.append((QRegularExpression(r"(?<!\*)\*(?!\*)[^\*]+\*(?!\*)"), italic))

        # 인용 > quote
        quote = QTextCharFormat()
        quote.setForeground(QColor(p["quote"]))
        quote.setFontItalic(True)
        self.rules.append((QRegularExpression(r"^\s*>\s+.*$"), quote))

        # 수평선 --- 또는 ___ 또는 ===
        hr = QTextCharFormat()
        hr.setForeground(QColor(p["hr"]))
        self.rules.append((QRegularExpression(r"^\s*([-_=*])\1{2,}\s*$"), hr))

    def highlightBlock(self, text: str) -> None:
        for pattern, fmt in self.rules:
            it = pattern.globalMatch(text)
            while it.hasNext():
                m = it.next()
                self.setFormat(m.capturedStart(), m.capturedLength(), fmt)

        # [P1-1 2026-05-11] 헤딩 라인 → 위/아래 breathing room + line-height
        # 일반 라인 → 기본 line-height 만 (130%)
        is_heading = any(p.match(text).hasMatch() for p in self.heading_patterns)
        block = self.currentBlock()
        if not block.isValid():
            return
        cur_bf = block.blockFormat()
        desired_top = 10 if is_heading else 0
        desired_bot = 4 if is_heading else 0
        desired_lh = 140 if is_heading else 130  # 헤딩은 더 여유롭게
        # 변화 필요 시에만 적용 — re-highlight loop 회피
        if (int(cur_bf.topMargin()) != desired_top
                or int(cur_bf.bottomMargin()) != desired_bot
                or int(cur_bf.lineHeight()) != desired_lh):
            new_bf = QTextBlockFormat(cur_bf)
            new_bf.setTopMargin(desired_top)
            new_bf.setBottomMargin(desired_bot)
            # 1 = ProportionalHeight (퍼센트)
            new_bf.setLineHeight(desired_lh, 1)
            cursor = QTextCursor(block)
            cursor.setBlockFormat(new_bf)


