def _file_icon_for_ext(filename: str) -> str:
    """[P2-2] 파일명 → 확장자 기반 이모지 (없으면 기본 📄)."""
    ext = os.path.splitext(filename)[1].lower()
    return _FILE_ICON_BY_EXT.get(ext, "📄")


# 13. 비디오 에디터 윈도우 클래스
class PythonHighlighter(QSyntaxHighlighter):
    """ 
    [VS Code Style] 파이썬 코드 구문 강조 (Vivid Dark Theme)
    - 색상을 더 진하고 선명하게 조정했습니다.
    """
    def __init__(self, document):
        super().__init__(document)

        self.highlighting_rules = []

        # --- 1. 색상 테마 정의 (VS Code Dark+ / One Dark Vivid) ---
        
        # [키워드] def, class, return, import 등 -> 진한 보라/핑크
        keyword_format = QTextCharFormat()
        keyword_format.setForeground(QColor("#C586C0")) 
        keyword_format.setFontWeight(QFont.Bold) # 굵게!
        
        # [제어문] if, else, for, while -> 진한 보라/핑크 (VS Code 스타일)
        control_flow_format = QTextCharFormat()
        control_flow_format.setForeground(QColor("#C586C0"))
        control_flow_format.setFontWeight(QFont.Bold)

        # [클래스명] MyClass -> 황금색/오렌지
        class_format = QTextCharFormat()
        class_format.setForeground(QColor("#E5C07B")) 
        class_format.setFontWeight(QFont.Bold)

        # [함수명] print(), my_func() -> 밝은 파랑
        function_format = QTextCharFormat()
        function_format.setForeground(QColor("#61AFEF")) 
        function_format.setFontWeight(QFont.Bold)

        # [문자열] "Hello" -> 선명한 녹색
        quotation_format = QTextCharFormat()
        quotation_format.setForeground(QColor("#98C379")) 

        # [주석] # Comment -> 짙은 녹색 (가독성 확보)
        comment_format = QTextCharFormat()
        comment_format.setForeground(QColor("#6A9955")) 
        comment_format.setFontItalic(True)

        # [숫자] 123, 3.14 -> 밝은 민트/라임
        number_format = QTextCharFormat()
        number_format.setForeground(QColor("#B5CEA8")) 
        
        # [데코레이터] @app.route -> 노란색
        decorator_format = QTextCharFormat()
        decorator_format.setForeground(QColor("#DCDCAA")) 

        # [self] -> 짙은 파랑
        self_format = QTextCharFormat()
        self_format.setForeground(QColor("#569CD6")) 
        self_format.setFontItalic(True)
        
        # [내장 함수/상수] None, True, False -> 짙은 파랑
        constant_format = QTextCharFormat()
        constant_format.setForeground(QColor("#569CD6"))
        constant_format.setFontWeight(QFont.Bold)

        # --- 2. 규칙 정의 (Regex) ---
        
        keywords = [
            "and", "as", "assert", "break", "continue", "del", "elif", "else", 
            "except", "finally", "for", "from", "global", "if", "import", "in", 
            "is", "lambda", "nonlocal", "not", "or", "pass", "raise", "return", 
            "try", "while", "with", "yield"
        ]
        
        constants = ["None", "True", "False"]
        
        # 정의 키워드
        def_keywords = ["def", "class", "async", "await"]

        def add_rule(pattern_str, fmt):
            pattern = QRegularExpression(pattern_str)
            self.highlighting_rules.append((pattern, fmt))

        # (1) 기본 키워드
        for word in keywords:
            add_rule(f"\\b{word}\\b", control_flow_format)
            
        for word in def_keywords:
            add_rule(f"\\b{word}\\b", keyword_format)
            
        for word in constants:
            add_rule(f"\\b{word}\\b", constant_format)

        # (2) self 키워드
        add_rule(r"\bself\b", self_format)

        # (3) 클래스 이름 (class 뒤에 오는 단어)
        add_rule(r"(?<=class\s)\w+", class_format)

        # (4) 함수 이름 (def 뒤에 오는 단어)
        add_rule(r"(?<=def\s)\w+", function_format)

        # (5) 데코레이터 (@...)
        add_rule(r"@[^\n]+", decorator_format)

        # (6) 숫자
        add_rule(r"\b[0-9]+\b", number_format)

        # (7) 문자열 (따옴표)
        add_rule(r"\".*?\"", quotation_format)
        add_rule(r"\'.*?\'", quotation_format)
        # 삼중 따옴표 문자열 (간단 처리)
        add_rule(r'""".*?"""', quotation_format)
        add_rule(r"'''.*?'''", quotation_format)

        # (8) 주석 (# 부터 끝까지)
        add_rule(r"#[^\n]*", comment_format)

    def highlightBlock(self, text):
        for pattern, format in self.highlighting_rules:
            match_iterator = pattern.globalMatch(text)
            while match_iterator.hasNext():
                match = match_iterator.next()
                self.setFormat(match.capturedStart(), match.capturedLength(), format)

# ----------------------------------------------------------------------
# 🎭 캐릭터 렌더러 (PyQt Implementation)
# ----------------------------------------------------------------------
class CodeEditorWindow(QWidget):
    """ EIDOS 프로젝트 파일 구조 관리 및 코드 편집을 위한 전용 창 """

    def __init__(self, parent=None, project_dir: str = "eidos_files/default_project", 
                 eidos_worker: Optional['EidosWorker'] = None, chat_history_deque: Optional[deque] = None):
        super().__init__(parent)
        self.project_root = os.path.abspath(project_dir)
        self.setWindowTitle(tr("code_title").format(dir=os.path.basename(project_dir)))
        self.setGeometry(200, 200, 1000, 700)
        
        self.runner_thread: Optional[CodeRunnerThread] = None
        self.current_file_path: Optional[str] = None
        self.eidos_worker = eidos_worker
        self.code_before_ai_modification: Optional[str] = None
        self.chat_history_deque = chat_history_deque if chat_history_deque else deque(maxlen=30)

        # [🔥 FIX] 클립보드 경로 변수 초기화 (이 줄을 추가하여 AttributeError 해결)
        self.clipboard_file_path: Optional[str] = None

        self.current_debug_session_errors: List[str] = []
        self._is_syncing_to_core = False

        # HTML 미리보기 debounce를 위한 타이머
        self.preview_update_timer = QTimer(self)
        self.preview_update_timer.setSingleShot(True)
        self.preview_update_timer.setInterval(500)

        self.is_dirty = False # 자동 저장을 위한 Dirty Flag

        self._init_ui()
        self._setup_signals()

        # 초기화
        self._refresh_file_tree()
        self._start_autosave()
        self._load_qa_list()
        # [Phase E 2026-05-03] 표준 단축키 (Ctrl+S / Ctrl+F)
        self._setup_standard_shortcuts()
        current_theme = load_theme_setting()
        self.apply_theme_to_terminal(current_theme)

    def _setup_standard_shortcuts(self):
        """[Phase E 2026-05-03] 표준 단축키: Ctrl+S 저장 / Ctrl+F 찾기."""
        try:
            from PySide6.QtGui import QShortcut, QKeySequence
            self._sc_save = QShortcut(QKeySequence("Ctrl+S"), self)
            self._sc_save.activated.connect(self._save_file)
            self._sc_find = QShortcut(QKeySequence("Ctrl+F"), self)
            self._sc_find.activated.connect(self._show_find_dialog)
        except Exception as e:
            print(f"⚠️ [CodeEditor] 단축키 셋업 실패 (graceful): {e}")

    def _wrap_with_header(self, title: str, content_widget):
        """[Phase UI 2026-05-03] 패널 wrapper — 섹션 헤더 + 본문 (구획 명확화).

        [P3-1 2026-05-11] QGraphicsDropShadowEffect 적용 — 카드 elevation.
        """
        from PySide6.QtWidgets import QFrame
        wrap = QFrame()
        wrap.setObjectName("EditorPanel")
        lay = QVBoxLayout(wrap)
        lay.setContentsMargins(0, 0, 0, 0)
        lay.setSpacing(0)
        header = QLabel(title)
        header.setObjectName("EditorPanelHeader")
        header.setMinimumHeight(28)
        lay.addWidget(header)
        lay.addWidget(content_widget, 1)
        try:
            shadow = QGraphicsDropShadowEffect(wrap)
            shadow.setBlurRadius(16)
            shadow.setOffset(0, 2)
            shadow.setColor(QColor(0, 0, 0, 90))
            wrap.setGraphicsEffect(shadow)
        except Exception as _e:
            print(f"[CodeEditorWindow] panel shadow failed: {_e}")
        return wrap

    def _show_find_dialog(self):
        """[Phase E 2026-05-03] Ctrl+F — 현재 에디터에서 텍스트 찾기."""
        try:
            from PySide6.QtWidgets import QInputDialog, QMessageBox
            from PySide6.QtGui import QTextCursor, QTextDocument
            editor = getattr(self, "code_editor", None) or getattr(
                self, "editor", None,
            )
            if editor is None:
                return
            text, ok = QInputDialog.getText(self, "찾기", "검색어:")
            if not ok or not text:
                return
            doc = editor.document()
            cursor = editor.textCursor()
            found = doc.find(text, cursor)
            if found.isNull():
                # 처음부터 다시
                cursor.movePosition(QTextCursor.MoveOperation.Start)
                found = doc.find(text, cursor)
            if found.isNull():
                QMessageBox.information(
                    self, "찾기 결과", f"'{text}' 를 찾을 수 없습니다.",
                )
                return
            editor.setTextCursor(found)
        except Exception as e:
            print(f"⚠️ [CodeEditor] 찾기 실패 (graceful): {e}")

