class PasteAwareTextEdit(QTextEdit):
    """[v3.2 2026-05-25] Ctrl+V (clipboard) + 드래그-드롭 (v3.3) 시 이미지/파일 가로채는 QTextEdit.

    오버라이드:
      • insertFromMimeData — Ctrl+V clipboard 처리
      • dragEnterEvent / dropEvent — 드래그-드롭 처리 (v3.3 2026-05-25)

    image 또는 file URLs 감지 시 parent 다이얼로그의 _attach_* 핸들러 호출.
    파일이 아닌 일반 텍스트는 super 로 위임 (기본 텍스트 paste·drag drop).

    사용처: ModificationDialog 의 request_edit (요청 사항 영역).
    """

    def __init__(self, parent=None):
        super().__init__(parent)
        # [v3.3] 드래그-드롭 활성 (QTextEdit default 도 True 지만 명시)
        self.setAcceptDrops(True)

    def insertFromMimeData(self, source):
        # 공통 처리 — Ctrl+V 와 drop 둘 다 같은 로직
        try:
            handled = self._process_attachments_from_mime(source)
            if not handled:
                super().insertFromMimeData(source)
        except Exception as e:
            print(f"⚠️ [PasteAwareTextEdit] insertFromMimeData 실패 (graceful·기본 paste 폴백): {e}")
            try:
                super().insertFromMimeData(source)
            except Exception:
                pass

    def _process_attachments_from_mime(self, source) -> bool:
        """mimeData → image / file urls 처리. 처리 성공 시 True (텍스트 paste skip).

        Ctrl+V 와 drop 둘 다 호출하는 공통 헬퍼.
        """
        handled = False
        # 1. 이미지 mimeData (clipboard 의 print screen / 캡쳐 이미지·또는 drag 의 image data)
        if source.hasImage():
            qimg = source.imageData()
            if qimg is not None and not qimg.isNull():
                parent = self._find_dialog_parent()
                if parent and hasattr(parent, "_attach_image_from_qimage"):
                    parent._attach_image_from_qimage(qimg)
                    handled = True
        # 2. 파일 URL list (탐색기에서 파일 복사 → 붙여넣기·또는 drag-drop)
        if source.hasUrls():
            parent = self._find_dialog_parent()
            if parent:
                accepted = 0
                for url in source.urls():
                    if not url.isLocalFile():
                        continue
                    path = url.toLocalFile()
                    if not path or not os.path.exists(path):
                        continue
                    # 확장자 기반 분기 — 이미지 / 텍스트
                    ext = os.path.splitext(path)[1].lower()
                    IMG_EXTS = {".png", ".jpg", ".jpeg", ".gif", ".bmp", ".webp"}
                    if ext in IMG_EXTS and hasattr(parent, "_attach_image_from_path"):
                        parent._attach_image_from_path(path)
                        accepted += 1
                    elif hasattr(parent, "_attach_file_path"):
                        parent._attach_file_path(path)
                        accepted += 1
                if accepted > 0:
                    handled = True
        return handled

    # ── [v3.3 2026-05-25] 드래그-드롭 ────────────────────────────────────
    def dragEnterEvent(self, event):
        """드래그 진입 — image 또는 url 있으면 accept (visual cue)."""
        try:
            mime = event.mimeData()
            if mime.hasImage() or mime.hasUrls():
                event.acceptProposedAction()
                return
        except Exception as e:
            print(f"⚠️ [PasteAwareTextEdit] dragEnterEvent 실패 (graceful): {e}")
        super().dragEnterEvent(event)

    def dragMoveEvent(self, event):
        try:
            mime = event.mimeData()
            if mime.hasImage() or mime.hasUrls():
                event.acceptProposedAction()
                return
        except Exception:
            pass
        super().dragMoveEvent(event)

    def dropEvent(self, event):
        """드롭 — Ctrl+V 와 같은 처리 (image/files 가로채기)."""
        try:
            mime = event.mimeData()
            handled = self._process_attachments_from_mime(mime)
            if handled:
                event.acceptProposedAction()
                return
        except Exception as e:
            print(f"⚠️ [PasteAwareTextEdit] dropEvent 실패 (graceful·super 폴백): {e}")
        super().dropEvent(event)

    def _find_dialog_parent(self):
        """[v3.4 2026-05-26] 첨부 핸들러 가진 parent 찾기 — parent chain 따라 올라감.

        QDialog 뿐 아니라 QMainWindow (예: CodeEditorV2Window) 도 매칭·
        duck typing 으로 _attach_image_from_qimage 메서드 보유한 모든 위젯 호환.
        """
        try:
            from PySide6.QtWidgets import QMainWindow
            p = self.parent()
            while p is not None:
                # 1. QDialog 또는 QMainWindow 면 우선 매칭
                if isinstance(p, (QDialog, QMainWindow)):
                    return p
                # 2. duck typing — 첨부 메서드 있는 위젯 매칭
                if hasattr(p, "_attach_image_from_qimage"):
                    return p
                p = p.parent() if hasattr(p, "parent") else None
        except Exception:
            pass
        return None


