def _automation_card_theme():
    """카드 공통 테마색 추출 (다른 카드들과 동일 패턴)."""
    import sys as _sys
    _mod = _sys.modules.get('__main__') or _sys.modules.get('eidos_chat_gui')
    _THEMES = getattr(_mod, 'THEMES', {})
    _load_ts = getattr(_mod, 'load_theme_setting', lambda: "Modern Dark")
    _theme_obj = _THEMES.get(_load_ts(), _THEMES.get("Modern Dark", {}))
    _c = _theme_obj.get("colors", {})
    is_dark = _theme_obj.get("is_dark", True)
    return {
        "card_bg": _c.get("bg_surface", "#1a1a2e" if is_dark else "#f1f5f9"),
        "accent": _c.get("accent_primary", "#7C3AED"),
        "accent_hover": _c.get("accent_hover", "#8B5CF6"),
        "text_primary": _c.get("text_primary", "#E5E7EB" if is_dark else "#1f2937"),
        "text_hint": _c.get("text_hint", "#6B7280" if is_dark else "#94A3B8"),
    }


class AutomationBlueprintCard(QFrame):
    """사용자가 "이 작업 자동화해줘" → 채팅에 뜨는 모식도 + 승인 카드.

    2.png 와 똑같은 모양의 블록 다이어그램(결정론적 SVG)을 보여주고,
    [✅ 승인 — 에이전트 조립] / [✕ 취소] 버튼을 제공한다. 승인 시
    approved_signal(task_text) emit → ChatWindow 가 verb 조립을 수행.
    """
    approved_signal = Signal(str)   # task_text
    cancelled_signal = Signal()

    def __init__(self, title: str, svg_bytes: bytes, task_text: str,
                 parent=None):
        super().__init__(parent)
        self.task_text = task_text
        self.setObjectName("AutomationBlueprintCard")
        t = _automation_card_theme()

        self.setStyleSheet(f"""
            QFrame#AutomationBlueprintCard {{
                border: 1.5px solid {t['accent']};
                border-radius: 12px;
                background-color: {t['card_bg']};
            }}
            QLabel#AbTitle {{ color: {t['accent']}; font-weight: bold; font-size: 13px; }}
            QLabel#AbHint  {{ color: {t['text_hint']}; font-size: 11px; }}
            QPushButton#AbApprove {{
                background-color: {t['accent']}; color: white; border: none;
                border-radius: 6px; padding: 7px 16px; font-weight: 600;
            }}
            QPushButton#AbApprove:hover {{ background-color: {t['accent_hover']}; }}
            QPushButton#AbApprove:disabled {{ background-color: {t['text_hint']}; }}
            QPushButton#AbCancel {{
                background-color: transparent; color: {t['text_hint']};
                border: 1px solid {t['text_hint']}; border-radius: 6px;
                padding: 6px 12px;
            }}
            QPushButton#AbCancel:hover {{ color: #ef4444; border-color: #ef4444; }}
        """)

        layout = QVBoxLayout(self)
        layout.setContentsMargins(14, 12, 14, 12)
        layout.setSpacing(8)

        title_lbl = QLabel(f"🤖 자동화 모식도 — {title}")
        title_lbl.setObjectName("AbTitle")
        title_lbl.setWordWrap(True)
        layout.addWidget(title_lbl)

        hint = QLabel("아래 블록 다이어그램대로 에이전트를 조립합니다. "
                      "검토 후 승인하세요.")
        hint.setObjectName("AbHint")
        hint.setWordWrap(True)
        layout.addWidget(hint)

        # 결정론적 SVG → QSvgWidget (다른 곳에서 검증된 경로)
        try:
            from PySide6.QtSvgWidgets import QSvgWidget
            svg_w = QSvgWidget()
            svg_w.load(svg_bytes if isinstance(svg_bytes, (bytes, bytearray))
                       else bytes(str(svg_bytes), "utf-8"))
            svg_w.setMinimumSize(QSize(560, 346))
            svg_w.setMaximumHeight(480)
            layout.addWidget(svg_w)
        except Exception as _e_svg:
            fb = QLabel(f"(모식도 렌더 실패: {_e_svg})")
            fb.setObjectName("AbHint")
            fb.setWordWrap(True)
            layout.addWidget(fb)

        btn_row = QHBoxLayout()
        btn_row.setSpacing(8)
        self.approve_btn = QPushButton("✅ 승인 — 에이전트 조립")
        self.approve_btn.setObjectName("AbApprove")
        self.approve_btn.setCursor(Qt.PointingHandCursor)
        self.approve_btn.clicked.connect(self._on_approve)
        btn_row.addWidget(self.approve_btn)

        self.cancel_btn = QPushButton("✕ 취소")
        self.cancel_btn.setObjectName("AbCancel")
        self.cancel_btn.setCursor(Qt.PointingHandCursor)
        self.cancel_btn.clicked.connect(self._on_cancel)
        btn_row.addWidget(self.cancel_btn)

        btn_row.addStretch()
        layout.addLayout(btn_row)

    def _on_approve(self):
        self.approve_btn.setEnabled(False)
        self.approve_btn.setText("🔧 조립 중…")
        self.cancel_btn.setEnabled(False)
        self.approved_signal.emit(self.task_text)

    def _on_cancel(self):
        self.cancelled_signal.emit()
        self.hide()
        self.deleteLater()


class AutomationAgentReadyCard(QFrame):
    """모식도 승인 → verb 조립 완료 → blueprint JSON 열기/실행 카드.

    [📂 열기] = 캔버스에 로드만, [▶ 바로 실행] = 로드 + 자동 실행.
    """
    open_requested = Signal(str)   # json_path
    run_requested = Signal(str)    # json_path

    def __init__(self, json_path: str, meta: dict, parent=None):
        super().__init__(parent)
        self.json_path = json_path
        self.setObjectName("AutomationAgentReadyCard")
        t = _automation_card_theme()
        accent = "#10b981"          # 완료 = 그린
        accent_hover = "#34d399"

        self.setStyleSheet(f"""
            QFrame#AutomationAgentReadyCard {{
                border: 1.5px solid {accent};
                border-radius: 12px;
                background-color: {t['card_bg']};
            }}
            QLabel#ArTitle {{ color: {accent}; font-weight: bold; font-size: 13px; }}
            QLabel#ArInfo  {{ color: {t['text_primary']}; font-size: 12px; }}
            QLabel#ArPath  {{ color: {t['text_hint']}; font-size: 10px; }}
            QPushButton#ArOpen {{
                background-color: transparent; color: {accent};
                border: 1px solid {accent}; border-radius: 6px;
                padding: 7px 16px; font-weight: 600;
            }}
            QPushButton#ArOpen:hover {{ background-color: {accent}; color: white; }}
            QPushButton#ArRun {{
                background-color: {accent}; color: white; border: none;
                border-radius: 6px; padding: 7px 16px; font-weight: 700;
            }}
            QPushButton#ArRun:hover {{ background-color: {accent_hover}; }}
        """)

        layout = QVBoxLayout(self)
        layout.setContentsMargins(14, 12, 14, 12)
        layout.setSpacing(6)

        title_lbl = QLabel("✅ 자동화 에이전트 조립 완료")
        title_lbl.setObjectName("ArTitle")
        layout.addWidget(title_lbl)

        verbs = meta.get("verbs", []) if isinstance(meta, dict) else []
        n_nodes = meta.get("n_nodes", 0) if isinstance(meta, dict) else 0
        n_edges = meta.get("n_edges", 0) if isinstance(meta, dict) else 0
        kinds = meta.get("node_kinds", {}) if isinstance(meta, dict) else {}
        chain = " → ".join(verbs) if verbs else "(단계 없음)"
        kind_line = (
            f"🔧 도구 {kinds.get('tool', 0)} · "
            f"💬 프롬프트 {kinds.get('prompt', 0)} · "
            f"✉️ 통신초안 {kinds.get('comms', 0)}"
        ) if kinds else ""
        info = QLabel(
            f"실행 흐름: {chain}\n"
            f"노드 {n_nodes}개 · 엣지 {n_edges}개"
            + (f"\n{kind_line}" if kind_line else ""))
        info.setObjectName("ArInfo")
        info.setWordWrap(True)
        layout.addWidget(info)

        path_lbl = QLabel(f"📄 {os.path.basename(json_path)}")
        path_lbl.setObjectName("ArPath")
        path_lbl.setToolTip(json_path)
        path_lbl.setWordWrap(True)
        layout.addWidget(path_lbl)

        btn_row = QHBoxLayout()
        btn_row.setSpacing(8)
        open_btn = QPushButton("📂 열기")
        open_btn.setObjectName("ArOpen")
        open_btn.setCursor(Qt.PointingHandCursor)
        open_btn.setToolTip("캔버스에 로드만 (실행 안 함)")
        open_btn.clicked.connect(lambda: self.open_requested.emit(self.json_path))
        btn_row.addWidget(open_btn)

        run_btn = QPushButton("▶ 바로 실행")
        run_btn.setObjectName("ArRun")
        run_btn.setCursor(Qt.PointingHandCursor)
        run_btn.setToolTip("캔버스에 로드 + 즉시 자동 실행")
        run_btn.clicked.connect(lambda: self.run_requested.emit(self.json_path))
        btn_row.addWidget(run_btn)

        btn_row.addStretch()
        layout.addLayout(btn_row)


class FullScreenCodeViewer(QDialog):
    """ 코드를 전체 화면으로 보여주는 다이얼로그 """
    def __init__(self, code_content, parent=None):
        super().__init__(parent)
        self.setWindowTitle(tr("fullcode_window_title"))
        self.setGeometry(100, 100, 1000, 800) # 큰 기본 크기

        layout = QVBoxLayout(self)
        layout.setContentsMargins(5, 5, 5, 5)

        # 코드 에디터 (읽기 전용)
        self.code_editor = QPlainTextEdit(self)
        self.code_editor.setPlainText(code_content)
        self.code_editor.setReadOnly(True)
        self.code_editor.setFont(QFont("Consolas", 12)) # 폰트 키움
        self.code_editor.setLineWrapMode(QPlainTextEdit.NoWrap)

        # 구문 강조 적용
        self.highlighter = PythonHighlighter(self.code_editor.document())

        layout.addWidget(self.code_editor)

        # 닫기 버튼
        button_box = QDialogButtonBox(QDialogButtonBox.StandardButton.Close)
        button_box.rejected.connect(self.reject)
        layout.addWidget(button_box)


# ══════════════════════════════════════════════════════════════════════════════

# ── [MilestoneRoadmapCard] 기획 카드 → 마일스톤 타임라인 ─────────────────────
MILESTONE_FILE = "eidos_files/eidos_milestones.json"

class MilestoneRoadmapCard(QFrame):
    """
    EIDOS가 생성한 로드맵을 편집 가능한 카드 UI로 표시.
    사용자가 내용 수정 후 승인하면 eidos_milestones.json 저장 +
    상단 타임라인 바 갱신 + 제어실 컨텍스트 주입.
    """
    approved = Signal(list)   # 승인된 steps 리스트

    def __init__(self, steps: list, top_goal: str, chat_window, parent=None):
        super().__init__(parent)
        self.chat_window = chat_window
        self.top_goal    = top_goal
        self._steps      = [dict(s) for s in steps]   # 편집용 복사본

        self.setObjectName("MilestoneRoadmapCard")
        self.setStyleSheet("""
            QFrame#MilestoneRoadmapCard {
                background: #0f172a;
                border: 1px solid #1e293b;
                border-radius: 10px;
                margin: 4px 0px;
            }
        """)

        root = QVBoxLayout(self)
        root.setContentsMargins(0, 0, 0, 0)
        root.setSpacing(0)

        # ── 헤더 ────────────────────────────────────────────────────
        hdr = QWidget()
        hdr.setStyleSheet("background: #1e1b4b; border-radius: 10px 10px 0 0; padding: 0px;")
        hdr_lay = QHBoxLayout(hdr)
        hdr_lay.setContentsMargins(16, 10, 12, 10)

        badge = QLabel("E")
        badge.setFixedSize(24, 24)
        badge.setAlignment(Qt.AlignmentFlag.AlignCenter)
        badge.setStyleSheet("background:#10b981;color:white;border-radius:6px;font-size:11pt;font-weight:bold;")

        title_col = QVBoxLayout()
        title_col.setSpacing(1)
        title_lbl = QLabel("실행 로드맵 초안")
        title_lbl.setStyleSheet("color:#c7d2fe;font-size:10pt;font-weight:bold;")
        sub_lbl   = QLabel("내용을 수정하고 승인하면 마일스톤으로 전환됩니다")
        sub_lbl.setStyleSheet("color:#6366f1;font-size:8pt;")
        title_col.addWidget(title_lbl)
        title_col.addWidget(sub_lbl)

        hdr_lay.addWidget(badge)
        hdr_lay.addSpacing(8)
        hdr_lay.addLayout(title_col)
        hdr_lay.addStretch()
        root.addWidget(hdr)

        # ── 목표 박스 ────────────────────────────────────────────────
        body = QWidget()
        body.setStyleSheet("background: transparent;")
        body_lay = QVBoxLayout(body)
        body_lay.setContentsMargins(16, 12, 16, 0)
        body_lay.setSpacing(8)

        goal_box = QFrame()
        goal_box.setStyleSheet("""
            QFrame {
                background:#0f2d1e;
                border-left: 3px solid #10b981;
                border-radius: 0 5px 5px 0;
                padding: 2px;
            }
        """)
        gb_lay = QVBoxLayout(goal_box)
        gb_lay.setContentsMargins(10, 7, 10, 7)
        gb_lay.setSpacing(2)
        QLabel("최종 목표", parent=goal_box).setStyleSheet("color:#6ee7b7;font-size:8pt;")
        gb_lay.addWidget(QLabel("최종 목표", parent=goal_box))
        goal_txt = QLabel(top_goal[:120])
        goal_txt.setStyleSheet("color:#a7f3d0;font-size:9.5pt;font-weight:bold;")
        goal_txt.setWordWrap(True)
        gb_lay.addWidget(goal_txt)
        body_lay.addWidget(goal_box)

        # ── Step 편집 위젯들 ─────────────────────────────────────────
        hint = QLabel("✎  제목과 설명을 직접 수정할 수 있습니다")
        hint.setStyleSheet("color:#10b981;font-size:8pt;")
        body_lay.addWidget(hint)

        steps_lbl = QLabel("실행 단계")
        steps_lbl.setStyleSheet("color:#6b7280;font-size:8pt;letter-spacing:1px;")
        body_lay.addWidget(steps_lbl)

        self._step_widgets = []   # (title_edit, desc_edit) 쌍

        STEP_COLORS = ["#4f46e5","#059669","#d97706","#0ea5e9","#8b5cf6","#dc2626"]

        for i, step in enumerate(self._steps):
            row = QHBoxLayout()
            row.setSpacing(8)

            # 번호 뱃지
            num_lbl = QLabel(str(i + 1))
            num_lbl.setFixedSize(24, 24)
            num_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)
            color = STEP_COLORS[i % len(STEP_COLORS)]
            num_lbl.setStyleSheet(
                f"background:{color};color:white;border-radius:12px;font-size:9pt;font-weight:bold;"
            )
            row.addWidget(num_lbl)
            row.setAlignment(num_lbl, Qt.AlignmentFlag.AlignTop)

            # 편집 카드
            card = QFrame()
            card.setStyleSheet(f"""
                QFrame {{
                    background:#1e293b;
                    border: 1px solid {color}55;
                    border-left: 3px solid {color};
                    border-radius: 6px;
                }}
            """)
            card_lay = QVBoxLayout(card)
            card_lay.setContentsMargins(10, 8, 10, 8)
            card_lay.setSpacing(4)

            title_edit = QLineEdit(step.get("title",""))
            title_edit.setStyleSheet("""
                QLineEdit {
                    background: transparent; border: none;
                    color: #f1f5f9; font-size: 10pt; font-weight: bold;
                }
                QLineEdit:focus { border-bottom: 1px solid #6366f1; }
            """)
            card_lay.addWidget(title_edit)

            desc_edit = QTextEdit()
            desc_edit.setPlainText(step.get("desc",""))
            desc_edit.setFixedHeight(52)
            desc_edit.setStyleSheet("""
                QTextEdit {
                    background: transparent; border: none;
                    color: #94a3b8; font-size: 8.5pt;
                }
                QTextEdit:focus { border-bottom: 1px solid #334155; }
            """)
            card_lay.addWidget(desc_edit)

            kpi_lbl = QLabel(f"완료 기준: {step.get('kpi','')}")
            kpi_lbl.setStyleSheet("color:#475569;font-size:8pt;")
            kpi_lbl.setWordWrap(True)
            card_lay.addWidget(kpi_lbl)

            row.addWidget(card, 1)
            body_lay.addLayout(row)

            self._step_widgets.append((title_edit, desc_edit, kpi_lbl, step))

        # ── 단계 추가 버튼 ─────────────────────────────────────────
        add_btn = QPushButton("＋  단계 추가")
        add_btn.setStyleSheet("""
            QPushButton {
                background: transparent;
                border: 1px dashed #334155;
                border-radius: 6px;
                color: #6b7280; font-size: 9pt;
                padding: 6px;
            }
            QPushButton:hover { border-color: #6366f1; color: #a5b4fc; }
        """)
        add_btn.clicked.connect(self._add_step)
        body_lay.addWidget(add_btn)
        self._body_lay  = body_lay
        self._add_btn   = add_btn
        self._step_colors = STEP_COLORS

        root.addWidget(body)

        # ── 풋터 ─────────────────────────────────────────────────────
        ftr = QWidget()
        ftr.setStyleSheet("background: transparent; border-top: 1px solid #1e293b;")
        ftr_lay = QHBoxLayout(ftr)
        ftr_lay.setContentsMargins(16, 10, 12, 12)

        note = QLabel("승인 시 상단 타임라인으로 전환 → Step 1 즉시 시작")
        note.setStyleSheet("color:#475569;font-size:8pt;")
        ftr_lay.addWidget(note, 1)

        regen_btn = QPushButton("↺  다시 생성")
        regen_btn.setFixedHeight(28)
        regen_btn.setStyleSheet("""
            QPushButton {
                background:#1e293b; border:1px solid #334155;
                color:#94a3b8; border-radius:5px; font-size:9pt; padding:0 12px;
            }
            QPushButton:hover { background:#334155; }
        """)
        regen_btn.clicked.connect(self._on_regen)

        approve_btn = QPushButton("승인  →")
        approve_btn.setFixedHeight(28)
        approve_btn.setStyleSheet("""
            QPushButton {
                background:#10b981; border:none;
                color:white; border-radius:5px;
                font-size:9pt; font-weight:bold; padding:0 16px;
            }
            QPushButton:hover { background:#059669; }
        """)
        approve_btn.clicked.connect(self._on_approve)

        ftr_lay.addWidget(regen_btn)
        ftr_lay.addSpacing(6)
        ftr_lay.addWidget(approve_btn)
        root.addWidget(ftr)

    def _add_step(self):
        """단계 추가."""
        idx = len(self._step_widgets) + 1
        new_step = {"title": f"새 단계 {idx}", "desc": "실행 내용을 입력하세요", "kpi": "완료 기준", "days": 7}
        self._steps.append(new_step)

        # 동적으로 레이아웃에 삽입 (_add_btn 바로 앞)
        row = QHBoxLayout()
        color = self._step_colors[(idx - 1) % len(self._step_colors)]
        num_lbl = QLabel(str(idx))
        num_lbl.setFixedSize(24, 24)
        num_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)
        num_lbl.setStyleSheet(f"background:{color};color:white;border-radius:12px;font-size:9pt;font-weight:bold;")
        row.addWidget(num_lbl)
        row.setAlignment(num_lbl, Qt.AlignmentFlag.AlignTop)

        card = QFrame()
        card.setStyleSheet(f"QFrame{{background:#1e293b;border:1px solid {color}55;border-left:3px solid {color};border-radius:6px;}}")
        card_lay = QVBoxLayout(card)
        card_lay.setContentsMargins(10, 8, 10, 8); card_lay.setSpacing(4)
        te = QLineEdit(new_step["title"])
        te.setStyleSheet("QLineEdit{background:transparent;border:none;color:#f1f5f9;font-size:10pt;font-weight:bold;}QLineEdit:focus{border-bottom:1px solid #6366f1;}")
        de = QTextEdit(); de.setPlainText(new_step["desc"]); de.setFixedHeight(52)
        de.setStyleSheet("QTextEdit{background:transparent;border:none;color:#94a3b8;font-size:8.5pt;}")
        kl = QLabel(f"완료 기준: {new_step['kpi']}"); kl.setStyleSheet("color:#475569;font-size:8pt;")
        card_lay.addWidget(te); card_lay.addWidget(de); card_lay.addWidget(kl)
        row.addWidget(card, 1)

        # _add_btn 앞에 삽입
        insert_idx = self._body_lay.count() - 1
        self._body_lay.insertLayout(insert_idx, row)
        self._step_widgets.append((te, de, kl, new_step))
        te.setFocus(); te.selectAll()

    def _collect_steps(self) -> list:
        """현재 편집 상태의 step 리스트 수집."""
        result = []
        for title_edit, desc_edit, kpi_lbl, orig in self._step_widgets:
            result.append({
                "title": title_edit.text().strip() or orig.get("title",""),
                "desc":  desc_edit.toPlainText().strip() or orig.get("desc",""),
                "kpi":   orig.get("kpi",""),
                "days":  orig.get("days", 7),
            })
        return result

    def _on_approve(self):
        """승인 → 마일스톤 저장 + 타임라인 갱신 + 컨텍스트 주입."""
        steps = self._collect_steps()
        if not steps:
            return

        import json, os
        data = {
            "top_goal":     self.top_goal,
            "current_step": 0,
            "steps":        steps,
            "created_at":   __import__("datetime").datetime.now().strftime("%Y-%m-%d %H:%M"),
        }
        try:
            os.makedirs("eidos_files", exist_ok=True)
            with open(MILESTONE_FILE, "w", encoding="utf-8") as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
        except Exception as e:
            print(f"  [Milestone] 저장 실패: {e}")

        # 제어실 컨텍스트에 현재 Step 주입
        _inject_milestone_context(data)

        # 상단 타임라인 바 갱신
        if self.chat_window and hasattr(self.chat_window, "milestone_bar"):
            self.chat_window.milestone_bar.load_milestones()

        # 승인 확인 메시지
        if self.chat_window:
            step1 = steps[0]["title"] if steps else ""
            self.chat_window.append_message(
                f"✅ 로드맵이 확정됐습니다. <b>Step 1: {step1}</b>부터 시작할게요.",
                "system"
            )

        self.approved.emit(steps)
        self.hide()

    def _on_regen(self):
        """다시 생성 — 채팅창에 재요청 메시지 전송."""
        if self.chat_window and hasattr(self.chat_window, "eidos_worker"):
            self.chat_window.eidos_worker.submit_task(
                self.chat_window.eidos_worker._generate_milestone_card_async(self.top_goal)
            )
        self.hide()


def _inject_milestone_context(data: dict):
    """현재 마일스톤 상태를 schedule_planner_context.json의 situation_internal에 주입."""
    import json, os
    steps       = data.get("steps", [])
    current_idx = data.get("current_step", 0)
    if not steps:
        return
    cur = steps[current_idx] if current_idx < len(steps) else None
    if not cur:
        return

    ctx_line = (
        f"[마일스톤 진행 상황] "
        f"전체 {len(steps)}단계 중 Step {current_idx + 1} 진행 중: "
        f"{cur['title']} — {cur['desc']} "
        f"(완료 기준: {cur.get('kpi','')})"
    )

    try:
        ctx_file = SCHEDULE_CONTEXT_FILE
        ctx = {}
        if os.path.exists(ctx_file):
            with open(ctx_file, "r", encoding="utf-8") as f:
                ctx = json.load(f)

        # situation_internal 앞에 마일스톤 줄 삽입 (기존 내용 유지)
        existing = ctx.get("situation_internal", "")
        # 이전 마일스톤 줄 제거 후 새로 삽입
        lines = [l for l in existing.split("\n") if "[마일스톤 진행 상황]" not in l]
        lines.insert(0, ctx_line)
        ctx["situation_internal"] = "\n".join(lines[:20])  # 최대 20줄

        os.makedirs(os.path.dirname(ctx_file) or ".", exist_ok=True)
        with open(ctx_file, "w", encoding="utf-8") as f:
            json.dump(ctx, f, ensure_ascii=False, indent=2)
        print(f"  [Milestone] 컨텍스트 주입: Step {current_idx + 1}/{len(steps)}")
    except Exception as e:
        print(f"  [Milestone] 컨텍스트 주입 실패: {e}")


def _load_milestones() -> dict:
    """eidos_milestones.json 로드. 없으면 빈 dict."""
    import json, os
    if not os.path.exists(MILESTONE_FILE):
        return {}
    try:
        with open(MILESTONE_FILE, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}


def _save_milestones(data: dict):
    """eidos_milestones.json 저장."""
    import json, os
    try:
        os.makedirs("eidos_files", exist_ok=True)
        with open(MILESTONE_FILE, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
    except Exception as e:
        print(f"  [Milestone] 저장 실패: {e}")


# ── [MilestoneBarWidget] 상단 타임라인 바 ────────────────────────────────────
class MilestoneBarWidget(QWidget):
    """
    ChatWindow 상단 목표 바 아래에 위치하는 가로 타임라인 바.
    마일스톤이 없으면 자동으로 숨김.
    """
    def __init__(self, chat_window, parent=None):
        super().__init__(parent)
        self.chat_window = chat_window
        self._data = {}

        self.setObjectName("MilestoneBar")
        self.setStyleSheet("""
            QWidget#MilestoneBar {
                background: transparent;
                border-bottom: 1px solid transparent;
            }
        """)  # 실제 색상은 set_theme_colors에서 적용

        outer = QHBoxLayout(self)
        outer.setContentsMargins(14, 8, 14, 8)
        outer.setSpacing(0)

        # 스크롤 가능하게
        scroll = QScrollArea()
        scroll.setWidgetResizable(True)
        scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
        scroll.setVerticalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
        scroll.setFrameShape(QFrame.NoFrame)
        scroll.setStyleSheet("background: transparent;")

        self._inner = QWidget()
        self._inner.setStyleSheet("background: transparent;")
        self._inner_lay = QHBoxLayout(self._inner)
        self._inner_lay.setContentsMargins(0, 0, 0, 0)
        self._inner_lay.setSpacing(0)
        self._inner_lay.addStretch()

        scroll.setWidget(self._inner)
        outer.addWidget(scroll)

        self.hide()  # 마일스톤 없으면 숨김
        self.load_milestones()

    def load_milestones(self):
        """파일에서 마일스톤 로드 후 UI 갱신."""
        self._data = _load_milestones()
        self._rebuild()

    def _rebuild(self):
        """타임라인 노드 재구성."""
        while self._inner_lay.count():
            item = self._inner_lay.takeAt(0)
            if item.widget():
                item.widget().deleteLater()
        steps   = self._data.get("steps", [])
        cur_idx = self._data.get("current_step", 0)
        if not steps:
            self.hide()
            return
        self.show()
        COLORS = ["#4f46e5","#059669","#d97706","#0ea5e9","#8b5cf6","#dc2626"]
        self._rebuild_v2(steps, cur_idx, COLORS)

    def _rebuild_v2(self, steps, cur_idx, COLORS):
        """실제 타임라인 노드 렌더링."""
        # 이전에 _rebuild에서 추가한 것들 제거 (이미 while로 제거됨)
        for i, step in enumerate(steps):
            color      = COLORS[i % len(COLORS)]
            is_done    = i < cur_idx
            is_current = i == cur_idx

            # 노드 + 레이블 컨테이너
            nw = QWidget()
            nw.setFixedWidth(70)
            nw_lay = QVBoxLayout(nw)
            nw_lay.setContentsMargins(0, 0, 0, 0)
            nw_lay.setSpacing(3)
            nw_lay.setAlignment(Qt.AlignmentFlag.AlignHCenter)

            node = QPushButton(str(i + 1))
            node.setFixedSize(26, 26)
            node.setCursor(Qt.CursorShape.PointingHandCursor)
            node.setToolTip(f"Step {i+1}: {step['title']}\n{step.get('desc','')[:60]}")

            if is_done:
                node.setStyleSheet(f"QPushButton{{background:{color};color:white;border-radius:13px;font-size:9pt;font-weight:bold;border:2px solid {color};}}")
            elif is_current:
                node.setStyleSheet(f"QPushButton{{background:{color};color:white;border-radius:13px;font-size:9pt;font-weight:bold;border:2px solid white;}}")
                try:
                    from PySide6.QtWidgets import QGraphicsDropShadowEffect
                    from PySide6.QtGui import QColor as _QC
                    g = QGraphicsDropShadowEffect(); g.setBlurRadius(14); g.setOffset(0,0); g.setColor(_QC(color))
                    node.setGraphicsEffect(g)
                except Exception:
                    pass
            else:
                node.setStyleSheet(f"QPushButton{{background:#1e293b;color:#475569;border-radius:13px;font-size:9pt;border:1px solid #334155;}}QPushButton:hover{{border-color:{color};color:{color};}}")

            idx_cap = i
            node.clicked.connect(lambda _, idx=idx_cap: self._on_node_click(idx))

            lbl = QLabel(step["title"][:10])
            lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)
            if is_current:
                lbl.setStyleSheet(f"font-size:7.5pt;color:{color};font-weight:bold;")
            elif is_done:
                lbl.setStyleSheet("font-size:7.5pt;color:#475569;text-decoration:line-through;")
            else:
                lbl.setStyleSheet("font-size:7.5pt;color:#334155;")

            nw_lay.addWidget(node, 0, Qt.AlignmentFlag.AlignHCenter)
            nw_lay.addWidget(lbl,  0, Qt.AlignmentFlag.AlignHCenter)
            self._inner_lay.addWidget(nw)

            # 연결선 (마지막 제외)
            if i < len(steps) - 1:
                line_w = QWidget()
                line_w.setFixedSize(30, 2)
                line_w.setStyleSheet(f"background:{'#334155' if not is_done else color};border-radius:1px;")
                # 수직 중앙에 오도록 컨테이너
                lc = QWidget(); lc.setFixedWidth(30)
                lc_lay = QVBoxLayout(lc); lc_lay.setContentsMargins(0,0,0,0)
                lc_lay.addStretch(); lc_lay.addWidget(line_w); lc_lay.addStretch()
                # line_w 자체가 13px (노드 반지름) 위치에 오도록 고정 높이
                lc.setFixedHeight(40)
                self._inner_lay.addWidget(lc)

        self._inner_lay.addStretch()

    def _on_node_click(self, idx: int):
        """노드 클릭 시 해당 Step 상세 툴팁 or 팝업."""
        if not self._data.get("steps"):
            return
        steps = self._data["steps"]
        if idx >= len(steps):
            return
        step = steps[idx]
        cur  = self._data.get("current_step", 0)
        status = "✅ 완료" if idx < cur else ("▶ 진행 중" if idx == cur else "⬜ 미시작")
        from PySide6.QtWidgets import QToolTip
        from PySide6.QtGui import QCursor
        QToolTip.showText(
            QCursor.pos(),
            f"<b>Step {idx+1}: {step['title']}</b><br>"
            f"{step.get('desc','')}<br>"
            f"<i>완료 기준: {step.get('kpi','')}</i><br>"
            f"상태: {status}"
        )


# 🌳 [PlanningTreeCard] 목표 트리뷰 기획 카드 (메인채팅창 인라인)
# ══════════════════════════════════════════════════════════════════════════════

class GoalNode:
    """기획 트리의 단일 노드 데이터 모델"""
    def __init__(self, title: str, detail: str = "", level: int = 0):
        import uuid
        self.title = title
        self.detail = detail
        self.level = level
        self.node_id = str(uuid.uuid4())[:8]
        self.children: list = []
        self.is_expanded = False
        self.is_loading = False


class GoalNodeWidget(QFrame):
    """단일 GoalNode를 렌더링하는 위젯. + 버튼 클릭 시 expand_requested 발생."""
    expand_requested = Signal(object)  # GoalNode

    # 테마별 색상 세트 정의
    LEVEL_STYLES_DARK = [
        ("#1a1f2e", "#5B8CFF", "#7EAAFF"), ("#1e2235", "#A78BFA", "#C4B5FD"),
        ("#1c2030", "#34D399", "#6EE7B7"), ("#1b1e2e", "#F97316", "#FCA96D"),
        ("#1a1d2c", "#EC4899", "#F9A8D4"),
    ]
    LEVEL_HOVER_BG_DARK = ["#1e2540", "#232848", "#20283a", "#1f2438", "#1e2236"]

    LEVEL_STYLES_LIGHT = [
        ("#eef2ff", "#6366f1", "#4338ca"), ("#f5f3ff", "#8b5cf6", "#5b21b6"),
        ("#f0fdf4", "#22c55e", "#14532d"), ("#fff7ed", "#f97316", "#9a3412"),
        ("#fdf2f8", "#ec4899", "#9d174d"),
    ]
    LEVEL_HOVER_BG_LIGHT = ["#e0e7ff", "#ede9fe", "#dcfce7", "#ffedd5", "#fce7f3"]

    def __init__(self, node: GoalNode, is_last_sibling: bool = False, is_dark: bool = True, parent=None):
        super().__init__(parent)
        self.node = node
        self.is_last_sibling = is_last_sibling  # └ vs ├ 결정
        self._hovered = False
        self._is_dark = is_dark
        self._build_ui()

    def _build_ui(self):
        # 테마에 따라 색상 세트 선택
        LEVEL_STYLES = self.LEVEL_STYLES_DARK if self._is_dark else self.LEVEL_STYLES_LIGHT
        LEVEL_HOVER_BG = self.LEVEL_HOVER_BG_DARK if self._is_dark else self.LEVEL_HOVER_BG_LIGHT

        idx = min(self.node.level, len(LEVEL_STYLES) - 1)
        self._bg, self._border_color, self._title_color = LEVEL_STYLES[idx]
        self._hover_bg = LEVEL_HOVER_BG[idx]

        # 레벨 0(최상위)은 들여쓰기 없음, 하위는 connector line 공간(20px) + level*20
        connector_width = 24 if self.node.level > 0 else 0
        indent = connector_width + (self.node.level - 1) * 24 if self.node.level > 0 else 0

        self.setObjectName("GoalNodeFrame")
        self._apply_style(False)
        self.setContentsMargins(connector_width, 0, 0, 0)

        # 외부 wrapper: connector line 공간 + 카드 본체
        outer = QHBoxLayout(self)
        outer.setContentsMargins(indent, 2, 0, 2)
        outer.setSpacing(0)

        # ── connector 라인 위젯 (레벨 > 0 일 때만) ──────────────────────────
        if self.node.level > 0:
            self._connector = _TreeConnector(
                border_color=self.LEVEL_STYLES[max(0, idx-1)][1],
                is_last=self.is_last_sibling,
            )
            self._connector.setFixedWidth(20)
            outer.addWidget(self._connector)
        else:
            self._connector = None

        # ── 카드 본체 ────────────────────────────────────────────────────────
        card = QFrame()
        card.setObjectName("GoalNodeCard")
        card.setStyleSheet(f"""
            QFrame#GoalNodeCard {{
                background-color: {self._bg};
                border-left: 4px solid {self._border_color};
                border-radius: 10px;
            }}
        """)
        card_layout = QVBoxLayout(card)
        card_layout.setContentsMargins(14, 10, 14, 10)
        card_layout.setSpacing(6)

        header = QHBoxLayout()
        header.setSpacing(10)

        level_names = ["최상위", "상위", "중위", "하위", "세부"]
        badge_text = level_names[min(self.node.level, len(level_names) - 1)]
        badge = QLabel(badge_text)
        badge.setFixedHeight(20)
        badge.setStyleSheet(f"""
            QLabel {{
                background-color: {self._border_color}33;
                color: {self._border_color};
                border: 1px solid {self._border_color}66;
                border-radius: 4px;
                padding: 0px 8px;
                font-size: 11px;
                font-weight: bold;
            }}
        """)
        header.addWidget(badge)

        self.title_label = QLabel(self.node.title)
        self.title_label.setStyleSheet(f"""
            QLabel {{
                color: {self._title_color};
                font-size: 14px;
                font-weight: bold;
                background: transparent;
            }}
        """)
        self.title_label.setWordWrap(True)
        header.addWidget(self.title_label, 1)

        # ── 수정 버튼 (hover 시 표시) ────────────────────────────────────
        self.edit_btn = QPushButton("✏️")
        self.edit_btn.setFixedSize(26, 26)
        self.edit_btn.setToolTip(tr("tooltip_edit_goal"))
        self.edit_btn.setVisible(False)
        self.edit_btn.setStyleSheet("""
            QPushButton {
                background-color: #1e2a3a;
                color: #93C5FD;
                border: 1px solid #2d4a6a;
                border-radius: 13px;
                font-size: 13px;
            }
            QPushButton:hover { background-color: #1e3a5f; border-color: #5B8CFF; }
        """)
        self.edit_btn.clicked.connect(self._on_edit_clicked)
        header.addWidget(self.edit_btn)

        # ── 삭제 버튼 (hover 시 표시) ────────────────────────────────────
        self.delete_btn = QPushButton("🗑")
        self.delete_btn.setFixedSize(26, 26)
        self.delete_btn.setToolTip(tr("tooltip_delete_goal"))
        self.delete_btn.setVisible(False)
        self.delete_btn.setStyleSheet("""
            QPushButton {
                background-color: #2a1e1e;
                color: #F87171;
                border: 1px solid #6a2d2d;
                border-radius: 13px;
                font-size: 13px;
            }
            QPushButton:hover { background-color: #3f1e1e; border-color: #EF4444; }
        """)
        self.delete_btn.clicked.connect(self._on_delete_clicked)
        header.addWidget(self.delete_btn)

        # ── + 버튼 (glow 효과) ──────────────────────────────────────────────
        self.expand_btn = QPushButton("＋")
        self.expand_btn.setFixedSize(34, 34)
        self.expand_btn.setToolTip(tr("tooltip_expand_goal"))
        self._btn_normal_style = f"""
            QPushButton {{
                background-color: {self._border_color}22;
                color: {self._border_color};
                border: 1.5px solid {self._border_color}99;
                border-radius: 17px;
                font-size: 18px;
                font-weight: bold;
            }}
            QPushButton:disabled {{ color: #555; border-color: #444; background: #1a1a2e; }}
        """
        self._btn_hover_style = f"""
            QPushButton {{
                background-color: {self._border_color}55;
                color: #ffffff;
                border: 2px solid {self._border_color};
                border-radius: 17px;
                font-size: 18px;
                font-weight: bold;
            }}
            QPushButton:disabled {{ color: #555; border-color: #444; background: #1a1a2e; }}
        """
        self.expand_btn.setStyleSheet(self._btn_normal_style)

        # glow 효과 (드롭 섀도우로 구현)
        self._glow = QGraphicsDropShadowEffect()
        self._glow.setBlurRadius(0)
        self._glow.setOffset(0, 0)
        self._glow.setColor(QColor(self._border_color))
        self.expand_btn.setGraphicsEffect(self._glow)

        self.expand_btn.clicked.connect(lambda: self.expand_requested.emit(self.node))

        # 버튼 hover 이벤트
        self.expand_btn.installEventFilter(self)

        header.addWidget(self.expand_btn)
        card_layout.addLayout(header)

        if self.node.detail:
            detail_label = QLabel(self.node.detail)
            detail_label.setWordWrap(True)
            detail_label.setStyleSheet("""
                QLabel {
                    color: #9CA3AF; font-size: 12px;
                    background: transparent; padding-left: 6px;
                }
            """)
            card_layout.addWidget(detail_label)

        outer.addWidget(card, 1)
        self._card = card

    def _apply_style(self, hovered: bool):
        """카드 hover 배경 전환"""
        pass  # 실제 배경 변경은 _card에서 처리

    def enterEvent(self, event):
        """카드 전체 hover → 배경 밝게 + 수정/삭제 버튼 표시"""
        self._hovered = True
        if hasattr(self, '_card'):
            self._card.setStyleSheet(f"""
                QFrame#GoalNodeCard {{
                    background-color: {self._hover_bg};
                    border-left: 4px solid {self._border_color};
                    border-radius: 10px;
                }}
            """)
        if hasattr(self, 'edit_btn'):
            self.edit_btn.setVisible(True)
            self.delete_btn.setVisible(True)
        super().enterEvent(event)

    def leaveEvent(self, event):
        self._hovered = False
        if hasattr(self, '_card'):
            self._card.setStyleSheet(f"""
                QFrame#GoalNodeCard {{
                    background-color: {self._bg};
                    border-left: 4px solid {self._border_color};
                    border-radius: 10px;
                }}
            """)
        if hasattr(self, 'edit_btn'):
            self.edit_btn.setVisible(False)
            self.delete_btn.setVisible(False)
        super().leaveEvent(event)

    def _on_edit_clicked(self):
        """제목 인라인 편집"""
        new_title, ok = QInputDialog.getText(
            self, "목표 수정", "새 제목을 입력하세요:", text=self.node.title
        )
        if ok and new_title.strip():
            self.node.title = new_title.strip()
            self.title_label.setText(self.node.title)

    def _on_delete_clicked(self):
        """이 노드를 트리에서 제거"""
        reply = QMessageBox.question(
            self, "삭제 확인",
            f"'{self.node.title[:30]}' 목표를 삭제하시겠습니까?",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No
        )
        if reply == QMessageBox.StandardButton.Yes:
            # 부모 레이아웃에서 자신을 제거
            layout = self.parentWidget().layout() if self.parentWidget() else None
            if layout:
                layout.removeWidget(self)
            self.hide()
            self.deleteLater()

    def eventFilter(self, obj, event):
        """+ 버튼 hover → glow + scale 느낌"""
        if obj is self.expand_btn:
            if event.type() == event.Type.Enter:
                self.expand_btn.setStyleSheet(self._btn_hover_style)
                self._glow.setBlurRadius(18)
            elif event.type() == event.Type.Leave:
                self.expand_btn.setStyleSheet(self._btn_normal_style)
                self._glow.setBlurRadius(0)
        return super().eventFilter(obj, event)

    def set_loading(self, loading: bool):
        self.node.is_loading = loading
        if loading:
            self.expand_btn.setText("⏳")
            self.expand_btn.setEnabled(False)
        else:
            self.expand_btn.setText("＋")
            self.expand_btn.setEnabled(True)

    def mark_expanded(self):
        self.expand_btn.setText("✓")
        self.expand_btn.setEnabled(False)
        self.expand_btn.setStyleSheet("""
            QPushButton {
                background-color: #16a34a22; color: #4ade80;
                border: 1px solid #4ade8088; border-radius: 17px; font-size: 14px;
            }
        """)
        if self._glow:
            self._glow.setBlurRadius(0)


class _TreeConnector(QWidget):
    """
    Notion/Workflowy 스타일 트리 연결선.
    레벨 > 0 인 노드 왼쪽에 그려집니다.
      ├─  (is_last=False)
      └─  (is_last=True)
    """
    def __init__(self, border_color: str, is_last: bool = False, parent=None):
        super().__init__(parent)
        self.border_color = border_color
        self.is_last = is_last
        self.setFixedWidth(20)

    def paintEvent(self, event: QPaintEvent):
        painter = QPainter(self)
        try:
            painter.setRenderHint(QPainter.Antialiasing)
            color = QColor(self.border_color)
            color.setAlpha(160)
            pen = QPen(color, 2)
            pen.setCapStyle(Qt.RoundCap)
            painter.setPen(pen)

            w = self.width()
            h = self.height()
            mid_y = h // 2
            mid_x = w // 2

            # 세로 라인: 상단 → 분기점 (is_last면 중앙까지, 아니면 하단까지)
            top_y = 0
            bottom_y = h if not self.is_last else mid_y
            painter.drawLine(mid_x, top_y, mid_x, bottom_y)

            # 가로 라인: 분기점 → 오른쪽
            painter.drawLine(mid_x, mid_y, w, mid_y)
        finally:
            painter.end()


# ══════════════════════════════════════════════════════════════════════════════
# 📅 [DailyScheduleCard] 오늘 할 일 트리뷰 카드 (앱 시작 시 자동 표시)
# ══════════════════════════════════════════════════════════════════════════════

class DailyScheduleCard(QFrame):
    """
    앱 시작 시 메인 채팅창에 자동으로 표시되는 오늘 할 일 트리뷰 카드.
    구조:
      최상위 → 오늘 날짜
        상위 Time1 → 🌅 오전 (09:00~12:00)
          하위 → 해당 시간대 작업들
        상위 Time2 → ☀️ 오후 (12:00~17:00)
          하위 → 해당 시간대 작업들
        상위 Time3 → 🌙 저녁 (17:00~23:00)
          하위 → 해당 시간대 작업들
    """

    # 시간대 정의: (아이콘, 레이블, 시작시간, 종료시간)
    TIME_SLOTS = [
        ("🌅", "오전",  "09:00", "12:00"),
        ("☀️", "오후",  "12:00", "17:00"),
        ("🌙", "저녁",  "17:00", "23:00"),
    ]

    # 시간대별 색상 (bg, border, title)
    # SLOT_COLORS, TASK_COLOR는 테마에 따라 _get_slot_colors()에서 동적 반환
    _SLOT_COLORS_DARK = [
        ("#1a1f2e", "#5B8CFF", "#7EAAFF"),
        ("#1c2030", "#F59E0B", "#FCD34D"),
        ("#1a1d2c", "#A78BFA", "#C4B5FD"),
    ]
    _SLOT_COLORS_LIGHT = [
        ("#e0e7ff", "#6366f1", "#4338ca"),
        ("#fef3c7", "#d97706", "#92400e"),
        ("#ede9fe", "#7c3aed", "#5b21b6"),
    ]
    _TASK_COLOR_DARK  = ("#1b1e2e", "#34D399", "#6EE7B7")
    _TASK_COLOR_LIGHT = ("#dcfce7", "#16a34a", "#14532d")

    @classmethod
    def _is_dark_theme(cls):
        import sys
        _mod = sys.modules.get('__main__') or sys.modules.get('eidos_chat_gui')
        THEMES = getattr(_mod, 'THEMES', {}) if _mod else {}
        load_ts = getattr(_mod, 'load_theme_setting', None)
        name = load_ts() if load_ts else 'Modern Dark'
        theme = THEMES.get(name, {})
        return theme.get('is_dark', True)

    @property
    def SLOT_COLORS(self):
        return self._SLOT_COLORS_DARK if self._is_dark_theme() else self._SLOT_COLORS_LIGHT

    @property
    def TASK_COLOR(self):
        return self._TASK_COLOR_DARK if self._is_dark_theme() else self._TASK_COLOR_LIGHT

    def __init__(self, tasks: list, chat_window, parent=None):
        """
        tasks: [{"time": "09:30", "text": "...", "checked": False}, ...]
        """
        super().__init__(parent)
        self.tasks = tasks
        self.chat_window = chat_window

        self.setObjectName("DailyScheduleCard")
        # 테마에 맞는 배경색 동적 적용
        import sys as _sys
        _mod = _sys.modules.get('__main__') or _sys.modules.get('eidos_chat_gui')
        _THEMES = getattr(_mod, 'THEMES', {}) if _mod else {}
        _lts = getattr(_mod, "load_theme_setting", None)
        _tname = _lts() if _lts else "Modern Dark"
        _tc = _THEMES.get(_tname, {}).get('colors', {})
        _is_dk = _THEMES.get(_tname, {}).get('is_dark', True)
        _card_bg = _tc.get('bg_surface', '#12151f' if _is_dk else '#ffffff')
        _card_border = _tc.get('border_subtle', '#2d3348' if _is_dk else '#e2e8f0')
        self.setStyleSheet(f"""
            QFrame#DailyScheduleCard {{
                background-color: {_card_bg};
                border: 1px solid {_card_border};
                border-radius: 12px;
            }}
        """)
        self.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)

        outer = QVBoxLayout(self)
        outer.setContentsMargins(16, 14, 16, 14)
        outer.setSpacing(10)

        # ── 헤더 ──────────────────────────────────────────────────────────
        hdr = QHBoxLayout()
        icon_lbl = QLabel("📅")
        icon_lbl.setStyleSheet("font-size:18px; background:transparent;")
        today = QDate.currentDate()
        _lang_d = app_settings.get("language", "ko")
        day_names = {
            "ko": ["월", "화", "수", "목", "금", "토", "일"],
            "en": ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"],
            "ja": ["月", "火", "水", "木", "金", "土", "日"],
        }.get(_lang_d, ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"])
        day_name = day_names[today.dayOfWeek() - 1]
        _today_label = {
            "ko": f"{today.toString('yyyy년 MM월 dd일')} ({day_name}) 오늘의 할 일",
            "en": f"{today.toString('MMM dd, yyyy')} ({day_name}) Today's Tasks",
            "ja": f"{today.toString('yyyy年MM月dd日')} ({day_name}) 今日のタスク",
        }.get(_lang_d, f"{today.toString('MMM dd, yyyy')} ({day_name}) Today's Tasks")
        title_lbl = QLabel(
            f"<b style='color:{'#7EAAFF' if self._is_dark_theme() else '#4338ca'}; font-size:14px;'>"
            f"{_today_label}</b>"
        )
        title_lbl.setStyleSheet("background:transparent;")

        add_btn = QPushButton(tr("btn_add_schedule_daily"))
        add_btn.setFixedHeight(26)
        _btn_bg = _tc.get('bg_raised', '#1e2235' if _is_dk else '#f1f5f9')
        _btn_txt = _tc.get('text_secondary', '#9CA3AF' if _is_dk else '#64748b')
        _btn_brd = _tc.get('border_subtle', '#374151' if _is_dk else '#e2e8f0')
        _btn_accent = _tc.get('accent_primary', '#5B8CFF' if _is_dk else '#6366f1')
        add_btn.setStyleSheet(f"""
            QPushButton {{
                background-color:{_btn_bg}; color:{_btn_txt};
                border:1px solid {_btn_brd}; border-radius:6px;
                padding:0 10px; font-size:11px;
            }}
            QPushButton:hover {{ color:{'#e5e7eb' if _is_dk else '#1e293b'}; border-color:{_btn_accent}; }}
        """)
        add_btn.clicked.connect(self._open_planner)

        hdr.addWidget(icon_lbl)
        hdr.addWidget(title_lbl)
        hdr.addStretch()
        hdr.addWidget(add_btn)
        outer.addLayout(hdr)

        sep = QFrame(); sep.setFrameShape(QFrame.HLine)
        sep.setStyleSheet(f"color:{_card_border};")
        outer.addWidget(sep)

        # ── 트리 스크롤 ───────────────────────────────────────────────────
        scroll = QScrollArea()
        scroll.setWidgetResizable(True)
        scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
        scroll.setStyleSheet(f"""
            QScrollArea {{ border:none; background:transparent; }}
            QScrollBar:vertical {{ background:{'#1a1f2e' if _is_dk else '#f1f5f9'}; width:6px; border-radius:3px; }}
            QScrollBar::handle:vertical {{ background:{'#3b4568' if _is_dk else '#cbd5e1'}; border-radius:3px; }}
        """)
        scroll.setMinimumHeight(200)
        scroll.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)

        container = QWidget()
        container.setStyleSheet("background:transparent;")
        self._tree_layout = QVBoxLayout(container)
        self._tree_layout.setContentsMargins(4, 4, 4, 4)
        self._tree_layout.setSpacing(4)

        # ── 최상위 노드 (오늘 날짜) ───────────────────────────────────────
        self._build_root_node(today)

        # ── 시간대 + 작업 노드 빌드 ──────────────────────────────────────
        self._build_time_slots(tasks)

        self._tree_layout.addStretch()
        scroll.setWidget(container)
        outer.addWidget(scroll)

        # ── 요약 상태줄 ───────────────────────────────────────────────────
        done = sum(1 for t in tasks if t.get("checked", False))
        total = len(tasks)
        self._status_lbl = QLabel(
            f"✅ 총 {total}개의 할 일  |  완료 {done}개  |  남은 할 일 {total - done}개"
        )
        self._status_lbl.setStyleSheet(
            "QLabel { color:#6B7280; font-size:11px; background:transparent; }"
        )
        outer.addWidget(self._status_lbl)

    # ── 빌더 헬퍼 ─────────────────────────────────────────────────────────

    def _build_root_node(self, today: QDate):
        """최상위 노드 (오늘 날짜)"""
        _lang_d2 = app_settings.get("language", "ko")
        day_names = {
            "ko": ["월", "화", "수", "목", "금", "토", "일"],
            "en": ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"],
            "ja": ["月", "火", "水", "木", "金", "土", "日"],
        }.get(_lang_d2, ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"])
        day_name = day_names[today.dayOfWeek() - 1]
        _badge = {"ko": "오늘", "en": "Today", "ja": "今日"}.get(_lang_d2, "Today")
        _date_str = {
            "ko": f"{today.toString('yyyy년 MM월 dd일')} ({day_name})",
            "en": f"{today.toString('MMM dd, yyyy')} ({day_name})",
            "ja": f"{today.toString('yyyy年MM月dd日')} ({day_name})",
        }.get(_lang_d2, f"{today.toString('MMM dd, yyyy')} ({day_name})")
        frame = self._make_node_frame(
            level=0,
            bg=self.SLOT_COLORS[0][0], border_color=self.SLOT_COLORS[0][1], title_color=self.SLOT_COLORS[0][2],
            badge=_badge,
            title=_date_str,
            detail="",
            is_last=False,
            checkable=False,
        )
        self._tree_layout.addWidget(frame)

    def _build_time_slots(self, tasks: list):
        """3개 시간대 + 각 작업 노드"""
        for slot_idx, (icon, label, start, end) in enumerate(self.TIME_SLOTS):
            is_last_slot = (slot_idx == len(self.TIME_SLOTS) - 1)
            bg, border, title_c = self.SLOT_COLORS[slot_idx]

            # 해당 시간대 작업 필터링
            slot_tasks = [
                t for t in tasks
                if self._in_slot(t.get("time", "00:00"), start, end)
            ]

            slot_frame = self._make_node_frame(
                level=1,
                bg=bg, border_color=border, title_color=title_c,
                badge=f"{icon} {label}",
                title=f"{start} ~ {end}",
                detail=f"{len(slot_tasks)}개의 할 일" if slot_tasks else "할 일 없음",
                is_last=is_last_slot,
                checkable=False,
            )
            self._tree_layout.addWidget(slot_frame)

            # 작업 노드들
            for task_idx, task in enumerate(slot_tasks):
                is_last_task = (task_idx == len(slot_tasks) - 1)
                tbg, tborder, ttitle = self.TASK_COLOR
                checked = task.get("checked", False)
                time_str = task.get("time", "??:??")
                text = task.get("text", "")

                task_frame = self._make_node_frame(
                    level=2,
                    bg=tbg, border_color=tborder, title_color=ttitle,
                    badge=time_str,
                    title=text,
                    detail="",
                    is_last=is_last_task,
                    checkable=True,
                    checked=checked,
                    task_data=task,
                )
                self._tree_layout.addWidget(task_frame)

    def _make_node_frame(
        self, level: int, bg: str, border_color: str, title_color: str,
        badge: str, title: str, detail: str,
        is_last: bool, checkable: bool, checked: bool = False,
        task_data: dict = None,
    ) -> QFrame:
        """범용 노드 프레임 생성"""
        wrapper = QFrame()
        wrapper.setStyleSheet("background:transparent; border:none;")

        outer_layout = QHBoxLayout(wrapper)
        outer_layout.setContentsMargins(level * 24, 2, 0, 2)
        outer_layout.setSpacing(0)

        # 커넥터 라인
        if level > 0:
            connector = _TreeConnector(
                border_color=self.SLOT_COLORS[0][1] if level == 1 else border_color,
                is_last=is_last
            )
            connector.setFixedWidth(20)
            outer_layout.addWidget(connector)

        # 카드 본체
        card = QFrame()
        card.setObjectName(f"DayNode_{level}")
        card.setStyleSheet(f"""
            QFrame#DayNode_{level} {{
                background-color: {bg};
                border-left: 4px solid {border_color};
                border-radius: 10px;
            }}
            QFrame#DayNode_{level}:hover {{
                background-color: {self._brighten(bg)};
            }}
        """)

        card_layout = QHBoxLayout(card)
        card_layout.setContentsMargins(14, 8, 14, 8)
        card_layout.setSpacing(10)

        # 뱃지
        badge_lbl = QLabel(badge)
        badge_lbl.setFixedHeight(20)
        badge_lbl.setStyleSheet(f"""
            QLabel {{
                background-color: {border_color}33;
                color: {border_color};
                border: 1px solid {border_color}66;
                border-radius: 4px;
                padding: 0px 8px;
                font-size: 11px;
                font-weight: bold;
            }}
        """)
        card_layout.addWidget(badge_lbl)

        # 제목
        title_lbl = QLabel(title)
        title_lbl.setStyleSheet(f"""
            QLabel {{
                color: {title_color if not checked else '#555'};
                font-size: {'13px' if level < 2 else '12px'};
                font-weight: {'bold' if level < 2 else 'normal'};
                background: transparent;
                {'text-decoration: line-through;' if checked else ''}
            }}
        """)
        title_lbl.setWordWrap(True)
        card_layout.addWidget(title_lbl, 1)

        if detail:
            detail_lbl = QLabel(f"  {detail}")
            detail_lbl.setStyleSheet("QLabel { color:#6B7280; font-size:11px; background:transparent; }")
            card_layout.addWidget(detail_lbl)

        # 체크박스 (작업 노드)
        if checkable and task_data is not None:
            cb = QCheckBox()
            cb.setChecked(checked)
            cb.setStyleSheet(f"""
                QCheckBox::indicator {{ width:16px; height:16px; border-radius:4px;
                    border: 2px solid {border_color}88; background: transparent; }}
                QCheckBox::indicator:checked {{ background: {border_color}; border-color: {border_color}; }}
            """)
            _task_ref = task_data
            _title_ref = title_lbl
            _bc = border_color
            def _on_check(state, t=_task_ref, lbl=_title_ref, bc=_bc):
                is_done = (state == Qt.Checked)
                t["checked"] = is_done
                lbl.setStyleSheet(f"""
                    QLabel {{
                        color: {'#555' if is_done else title_color};
                        font-size: 12px; background: transparent;
                        {'text-decoration: line-through;' if is_done else ''}
                    }}
                """)
                self._sync_to_planner(t)
            cb.stateChanged.connect(_on_check)
            card_layout.addWidget(cb)

        outer_layout.addWidget(card, 1)
        return wrapper

    @staticmethod
    def _brighten(hex_color: str) -> str:
        """hex 색상을 약간 밝게"""
        try:
            c = QColor(hex_color)
            return QColor(
                min(255, c.red() + 12),
                min(255, c.green() + 12),
                min(255, c.blue() + 25),
            ).name()
        except Exception:
            return hex_color

    @staticmethod
    def _in_slot(time_str: str, start: str, end: str) -> bool:
        """time_str이 [start, end) 범위인지 확인 — 정수 변환으로 비교"""
        def to_minutes(t: str) -> int:
            try:
                h, m = t.strip().split(":")
                return int(h) * 60 + int(m)
            except Exception:
                return -1
        t = to_minutes(time_str)
        s = to_minutes(start)
        e = to_minutes(end)
        return s <= t < e

    def _sync_to_planner(self, task_data: dict):
        """체크 상태를 플래너 JSON에 저장하고 좌측 패널 갱신"""
        try:
            today_str = QDate.currentDate().toString("yyyy-MM-dd")
            full_data = {}
            if os.path.exists(PLANNER_FILE):
                with open(PLANNER_FILE, "r", encoding="utf-8") as f:
                    full_data = json.load(f)

            day_tasks = full_data.get(today_str, [])
            for t in day_tasks:
                if t.get("time") == task_data.get("time") and t.get("text") == task_data.get("text"):
                    t["checked"] = task_data["checked"]
                    break

            with open(PLANNER_FILE, "w", encoding="utf-8") as f:
                json.dump(full_data, f, ensure_ascii=False, indent=2)

            # 좌측 패널 갱신
            if self.chat_window:
                self.chat_window._load_planner_data(QDate.currentDate())

        except Exception as e:
            print(f"⚠️ [DailyScheduleCard] 플래너 동기화 실패: {e}")

    def _open_planner(self):
        """+ 일정 추가 버튼 → 좌측 패널 포커스 (입력 다이얼로그)"""
        if self.chat_window:
            try:
                self.chat_window._add_schedule_item()
            except Exception:
                pass


class PlanningTreeCard(QFrame):
    """
    메인 채팅창에 인라인으로 표시되는 목표 트리뷰 기획 카드.
    ChatWindow._active_planning_card 에 등록되어,
    on_eidos_response() 가 기획 응답을 이 카드로 라우팅합니다.
    """
    expand_requested = Signal(object, object)  # (GoalNode, PlanningTreeCard)

    def __init__(self, top_goal: str, chat_window, parent=None):
        super().__init__(parent)
        self.chat_window = chat_window
        self.top_goal = top_goal
        self._node_widget_map: dict = {}   # node_id → GoalNodeWidget
        # 현재 분해 대기 중인 노드 (+ 버튼 누른 것)
        self._pending_node: GoalNode = None

        self.setObjectName("PlanningTreeCard")

        # 전역에서 현재 테마 객체를 가져와 동적 스타일링
        import sys
        _mod = sys.modules.get('__main__') or sys.modules.get('eidos_chat_gui')
        _THEMES = getattr(_mod, 'THEMES', {})
        _load_ts = getattr(_mod, 'load_theme_setting', lambda: "Modern Dark")
        _theme_name = _load_ts()
        _theme_obj = _THEMES.get(_theme_name, _THEMES.get("Modern Dark", {}))
        _c = _theme_obj.get("colors", {})
        self.is_dark = _theme_obj.get("is_dark", True)

        card_bg = _c.get("bg_surface", "#12151f" if self.is_dark else "#f8fafc")
        border = _c.get("border_subtle", "#2d3348" if self.is_dark else "#e2e8f0")
        scroll_bg = _c.get("bg_raised", "#1a1f2e" if self.is_dark else "#f1f5f9")
        scroll_handle = _c.get("border_subtle", "#3b4568" if self.is_dark else "#cbd5e1")

        self.setStyleSheet(f"""
            QFrame#PlanningTreeCard {{
                background-color: {card_bg};
                border: 1px solid {border};
                border-radius: 12px;
            }}
        """)
        # 카드가 채팅창의 가용 세로 공간을 최대한 차지하도록
        self.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)

        outer = QVBoxLayout(self)
        outer.setContentsMargins(16, 14, 16, 14)
        outer.setSpacing(10)

        # 헤더
        hdr = QHBoxLayout()
        icon = QLabel("🌳")
        icon.setStyleSheet("font-size:18px; background:transparent;")
        title = QLabel(tr("planning_tree_title"))
        title.setStyleSheet("background:transparent;")
        export_btn = QPushButton(tr("btn_export_tree"))
        export_btn.setFixedHeight(26)
        export_btn.setStyleSheet("""
            QPushButton {
                background-color:#1e2235; color:#9CA3AF;
                border:1px solid #374151; border-radius:6px;
                padding:0 10px; font-size:11px;
            }
            QPushButton:hover { color:#e5e7eb; border-color:#5B8CFF; }
        """)
        export_btn.clicked.connect(self._export_tree)
        hdr.addWidget(icon); hdr.addWidget(title); hdr.addStretch(); hdr.addWidget(export_btn)
        outer.addLayout(hdr)

        sep = QFrame(); sep.setFrameShape(QFrame.HLine)
        sep.setStyleSheet("color:#2d3348;")
        outer.addWidget(sep)

        # 트리 스크롤 영역 — 부모(채팅창) 높이에 맞게 자동 확장
        self.tree_scroll = QScrollArea()
        self.tree_scroll.setWidgetResizable(True)
        self.tree_scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
        self.tree_scroll.setStyleSheet("""
            QScrollArea { border:none; background:transparent; }
            QScrollBar:vertical { background:#1a1f2e; width:6px; border-radius:3px; }
            QScrollBar::handle:vertical { background:#3b4568; border-radius:3px; }
        """)
        self.tree_scroll.setMinimumHeight(300)
        # 스크롤 영역이 세로 방향으로 최대한 늘어나도록 설정
        self.tree_scroll.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)

        self.tree_container = QWidget()
        self.tree_container.setStyleSheet("background:transparent;")
        self.tree_layout = QVBoxLayout(self.tree_container)
        self.tree_layout.setContentsMargins(4, 4, 4, 4)
        self.tree_layout.setSpacing(4)
        self.tree_layout.addStretch()
        self.tree_scroll.setWidget(self.tree_container)
        outer.addWidget(self.tree_scroll)

        # 상태 표시줄
        self.status_label = QLabel(tr("planning_tree_generating"))
        self.status_label.setStyleSheet("QLabel { color:#6B7280; font-size:11px; background:transparent; }")
        outer.addWidget(self.status_label)

    # ── 퍼블릭 API ──────────────────────────────────────────

    def populate_top_level(self, goals: list):
        """최초 top+sub 목표 리스트로 트리 초기화"""
        self.status_label.setText(tr("planning_tree_goals_done").format(count=len(goals)))
        for i, g in enumerate(goals):
            node = GoalNode(title=g.get("title",""), detail=g.get("detail",""), level=g.get("level",0))
            is_last = (i == len(goals) - 1)
            self._insert_node(node, parent_node_id=None, is_last=is_last)

    def add_children_to_node(self, parent_node: GoalNode, children: list):
        """+ 클릭 → AI 응답 후 하위 목표 삽입"""
        parent_widget = self._node_widget_map.get(parent_node.node_id)
        if parent_widget:
            parent_widget.mark_expanded()
        for i, c in enumerate(children):
            child = GoalNode(title=c.get("title",""), detail=c.get("detail",""), level=parent_node.level+1)
            parent_node.children.append(child)
            is_last = (i == len(children) - 1)
            self._insert_node(child, parent_node_id=parent_node.node_id, is_last=is_last)
        self.status_label.setText(tr("planning_tree_decompose_done").format(title=parent_node.title[:20], count=len(children)))
        QTimer.singleShot(50, lambda: self.tree_scroll.verticalScrollBar().setValue(
            self.tree_scroll.verticalScrollBar().maximum()))

    def set_status(self, text: str):
        self.status_label.setText(text)

    # ── 내부 헬퍼 ─────────────────────────────────────────

    def _insert_node(self, node: GoalNode, parent_node_id, is_last: bool = False):
        nw = GoalNodeWidget(node, is_last_sibling=is_last, is_dark=self.is_dark)
        nw.expand_requested.connect(self._on_expand_requested)
        self._node_widget_map[node.node_id] = nw

        count = self.tree_layout.count()
        if count > 0:
            last = self.tree_layout.itemAt(count - 1)
            if last and last.spacerItem():
                self.tree_layout.takeAt(count - 1)

        if parent_node_id is None:
            self.tree_layout.addWidget(nw)
        else:
            parent_w = self._node_widget_map.get(parent_node_id)
            if parent_w:
                insert_at = self.tree_layout.indexOf(parent_w) + 1
                while insert_at < self.tree_layout.count():
                    item = self.tree_layout.itemAt(insert_at)
                    w = item.widget() if item else None
                    if w and isinstance(w, GoalNodeWidget) and w.node.level > parent_w.node.level:
                        insert_at += 1
                    else:
                        break
                self.tree_layout.insertWidget(insert_at, nw)
            else:
                self.tree_layout.addWidget(nw)

        self.tree_layout.addStretch()

    def _on_expand_requested(self, node: GoalNode):
        if node.is_loading or node.is_expanded:
            return
        node.is_loading = True
        node.is_expanded = True
        nw = self._node_widget_map.get(node.node_id)
        if nw:
            nw.set_loading(True)
        self.status_label.setText(tr("planning_tree_decomposing").format(title=node.title[:25]))
        self._pending_node = node
        # ChatWindow에 분해 요청 위임
        self.chat_window._request_goal_decomposition(node, self)

    def _export_tree(self):
        """
        기획 트리를 프로젝트 관리창으로 내보냅니다.
        트리의 각 노드를 QTreeWidgetItem 계층으로 변환하여 ProjectManagerDialog에 삽입합니다.
        """
        # 1. 노드 위젯 수집 (level 순서대로)
        nodes: list[GoalNodeWidget] = []
        for i in range(self.tree_layout.count()):
            item = self.tree_layout.itemAt(i)
            w = item.widget() if item else None
            if w and isinstance(w, GoalNodeWidget):
                nodes.append(w)

        if not nodes:
            QMessageBox.information(self, tr("msg_export_empty_title"), tr("msg_export_empty_body"))
            return

        # 2. ChatWindow를 통해 ProjectManagerDialog 열기
        chat_win = self.chat_window
        if not hasattr(chat_win, 'eidos_worker'):
            QMessageBox.warning(self, tr("msg_export_pm_error_title"), tr("msg_export_pm_error_body"))
            return

        dialog = ProjectManagerDialog(chat_win, worker=chat_win.eidos_worker)
        # [버그 수정] 기획 내보내기 경로에서도 실행 버튼이 작동하도록 시그널 연결
        dialog.execution_requested.connect(chat_win._execute_from_project)

        # 3. 트리 노드를 QTreeWidgetItem 계층으로 변환하여 삽입
        # level별로 스택을 유지하며 부모-자식 관계 구성
        level_stack: dict[int, QTreeWidgetItem] = {}  # level → 현재 부모 item

        for nw in nodes:
            lvl = nw.node.level
            tree_item = QTreeWidgetItem()
            tree_item.setText(0, nw.node.title)
            detail = nw.node.detail or ""
            tree_item.setData(0, Qt.ItemDataRole.UserRole, {
                "prompt": detail,
                "files": [],
                "output_files": [],
                "subtasks": [],
                "status": "TODO",
            })

            if lvl == 0 or lvl - 1 not in level_stack:
                # 최상위 or 부모가 없으면 root에 추가
                dialog.tree_widget.addTopLevelItem(tree_item)
            else:
                parent_item = level_stack[lvl - 1]
                parent_item.addChild(tree_item)
                parent_item.setExpanded(True)

            level_stack[lvl] = tree_item
            # 현재 레벨 이하 스택 초기화 (새 가지가 시작될 때)
            for deeper in list(level_stack.keys()):
                if deeper > lvl:
                    del level_stack[deeper]

            dialog._update_item_visuals(tree_item)

        # 4. 다이얼로그 표시
        QMessageBox.information(
            self, "내보내기 완료",
            f"'{self.top_goal[:30]}' 기획이 프로젝트 관리창으로 이동되었습니다.\n"
            f"총 {len(nodes)}개의 목표가 추가되었습니다."
        )
        dialog.exec()

        # [Fix] 내보내기 완료 후 ChatWindow의 _active_planning_card 초기화
        # → 이후 새 기획 요청이 들어왔을 때 재진입 차단 해제
        if self.chat_window and hasattr(self.chat_window, "_active_planning_card"):
            self.chat_window._active_planning_card = None
            self.chat_window._planning_mode = None


class CodeFixResultCard(QFrame):
    """
    코드 파일 첨부 → AI 핀셋 수정 결과를 채팅에 표시하는 카드.
    수정된 파일 내용을 미리보기하고, 원본 파일에 덮어쓰거나 다른 이름으로 저장할 수 있다.
    """

    def __init__(self, original_path: str, fixed_code: str, summary: str, parent=None):
        super().__init__(parent)
        self.original_path = original_path   # 원본 파일 절대경로
        self.fixed_code = fixed_code         # AI가 수정한 전체 코드

        self.setObjectName("CodeFixResultCard")

        # 전역에서 현재 테마 객체를 가져와 동적 스타일링
        import sys
        _mod = sys.modules.get('__main__') or sys.modules.get('eidos_chat_gui')
        _THEMES = getattr(_mod, 'THEMES', {})
        _load_ts = getattr(_mod, 'load_theme_setting', lambda: "Modern Dark")
        _theme_name = _load_ts()
        _theme_obj = _THEMES.get(_theme_name, _THEMES.get("Modern Dark", {}))
        _c = _theme_obj.get("colors", {})
        is_dark = _theme_obj.get("is_dark", True)

        card_bg = _c.get("bg_surface", "#1a1a2e" if is_dark else "#f1f5f9")
        accent = _c.get("accent_primary", "#a78bfa")
        accent_light = _c.get("accent_hover", "#c4b5fd")
        text_hint = _c.get("text_hint", "#6b7280")
            
        self.setStyleSheet(f"""
            QFrame#CodeFixResultCard {{
                border: 1.5px solid {accent};
                border-radius: 12px;
                background-color: {card_bg};
            }}
            QLabel#CardTitle {{ color: {accent}; font-weight: bold; font-size: 13px; }}
            QLabel#SummaryLabel {{ color: {accent_light}; font-size: 11px; }}
            QLabel#PathLabel {{ color: {text_hint}; font-size: 10px; }}
        """)

        layout = QVBoxLayout(self)
        layout.setContentsMargins(14, 10, 14, 12)
        layout.setSpacing(8)

        # ── 헤더 ──────────────────────────────────────────────────
        header = QHBoxLayout()
        title = QLabel(tr("code_fix_title"))
        title.setObjectName("CardTitle")
        header.addWidget(title)
        header.addStretch()

        self.expand_btn = QPushButton(tr("btn_preview"))
        self.expand_btn.setCheckable(True)
        self.expand_btn.clicked.connect(self._toggle_preview)
        header.addWidget(self.expand_btn)

        layout.addLayout(header)

        # ── 파일 경로 ─────────────────────────────────────────────
        fname = os.path.basename(original_path)
        path_label = QLabel(f"📄 {fname}  ({original_path})")
        path_label.setObjectName("PathLabel")
        path_label.setWordWrap(True)
        layout.addWidget(path_label)

        # ── 수정 요약 ─────────────────────────────────────────────
        summary_label = QLabel(summary or tr("lbl_fix_default_summary"))
        summary_label.setObjectName("SummaryLabel")
        summary_label.setWordWrap(True)
        layout.addWidget(summary_label)

        # ── 코드 미리보기 (접혀 있음) ─────────────────────────────
        self.preview_edit = QPlainTextEdit()
        self.preview_edit.setPlainText(fixed_code)
        self.preview_edit.setReadOnly(True)
        self.preview_edit.setFont(QFont("Consolas", 9))
        self.preview_edit.setMinimumHeight(200)
        self.preview_edit.setMaximumHeight(420)
        code_bg = _c.get("bg_input", "#0d0d1a" if is_dark else "#f8fafc")
        code_fg = _c.get("text_primary", "#d4d4d4" if is_dark else "#334155")
        self.preview_edit.setStyleSheet(
            f"background-color: {code_bg}; color: {code_fg}; border-radius: 6px; padding: 8px;"
        )
        self.preview_edit.setVisible(False)
        layout.addWidget(self.preview_edit)

        # ── 버튼 행 ───────────────────────────────────────────────
        btn_row = QHBoxLayout()

        overwrite_btn = QPushButton(tr("btn_save_to_original"))
        overwrite_btn.clicked.connect(self._overwrite_original)
        btn_row.addWidget(overwrite_btn)

        saveas_btn = QPushButton(tr("btn_save_as"))
        saveas_btn.clicked.connect(self._save_as)
        btn_row.addWidget(saveas_btn)

        copy_btn = QPushButton(tr("btn_copy"))
        copy_btn.clicked.connect(self._copy_code)
        btn_row.addWidget(copy_btn)

        btn_row.addStretch()
        layout.addLayout(btn_row)

    def _toggle_preview(self, checked: bool):
        self.preview_edit.setVisible(checked)
        self.expand_btn.setText(tr("btn_collapse") if checked else tr("btn_preview"))

    def _overwrite_original(self):
        reply = QMessageBox.question(
            self, tr("msg_overwrite_confirm_title"),
            tr("msg_overwrite_confirm_body").format(name=os.path.basename(self.original_path)),
            QMessageBox.Yes | QMessageBox.No
        )
        if reply == QMessageBox.Yes:
            try:
                with open(self.original_path, 'w', encoding='utf-8') as f:
                    f.write(self.fixed_code)
                QMessageBox.information(self, tr("msg_save_ok_title"), tr("msg_save_ok_body").format(name=os.path.basename(self.original_path)))
            except Exception as e:
                QMessageBox.critical(self, tr("msg_save_error_title2"), tr("msg_save_error_body2").format(error=e))

    def _save_as(self):
        default_name = os.path.splitext(self.original_path)[0] + "_fixed" + os.path.splitext(self.original_path)[1]
        path, _ = QFileDialog.getSaveFileName(self, tr("dialog_save_as_title"), default_name)
        if path:
            try:
                with open(path, 'w', encoding='utf-8') as f:
                    f.write(self.fixed_code)
                QMessageBox.information(self, tr("msg_save_ok_title"), tr("msg_save_ok_body").format(name=os.path.basename(path)))
            except Exception as e:
                QMessageBox.critical(self, tr("msg_save_error_title2"), tr("msg_save_error_body2").format(error=e))

    def _copy_code(self):
        QApplication.clipboard().setText(self.fixed_code)


class FeatureSuggestionCard(QFrame):
    """
    코드 파일 첨부 + 기능 추가 요청 시 채팅에 표시되는 연두색 제안 카드.
    각 제안마다 "이 기능 추가하기" 버튼으로 즉시 핀셋 수정 파이프라인 연결.
    여러 버튼을 동시에 클릭하면 큐에 쌓아 순서대로 처리.
    """

    def __init__(self, file_path: str, suggestions: list, chat_window, parent=None):
        """
        suggestions: [{"title": str, "description": str, "why": str}, ...]
        chat_window: ChatWindow 인스턴스 (핀셋 수정 요청 위임용)
        """
        super().__init__(parent)
        self.file_path = file_path
        self.suggestions = suggestions
        self.chat_window = chat_window

        # 다중 요청 큐 & 버튼 레퍼런스 관리
        self._request_queue: list = []          # (suggestion, btn) 튜플 큐
        self._processing = False                # 현재 처리 중 여부
        self._btn_map: dict = {}               # suggestion title → QPushButton

        self.setObjectName("FeatureSuggestionCard")

        # 전역에서 현재 테마 객체를 가져와 동적 스타일링
        import sys
        _mod = sys.modules.get('__main__') or sys.modules.get('eidos_chat_gui')
        _THEMES = getattr(_mod, 'THEMES', {})
        _load_ts = getattr(_mod, 'load_theme_setting', lambda: "Modern Dark")
        _theme_name = _load_ts()
        _theme_obj = _THEMES.get(_theme_name, _THEMES.get("Modern Dark", {}))
        _c = _theme_obj.get("colors", {})
        is_dark = _theme_obj.get("is_dark", True)

        # Feature card is green-themed
        accent_green = "#4ade80" if is_dark else "#16a34a"
        bg_green_dark = "#0f1f14" if is_dark else "#f0fdf4"
        border_green = "#1f3a25" if is_dark else "#86efac"
        bg_green_item = "#162318" if is_dark else "#dcfce7"
        title_green = "#86efac" if is_dark else "#15803d"
        desc_green = "#d1fae5" if is_dark else "#14532d"
        btn_bg = "#166534" if is_dark else "#22c55e"
        btn_fg = "#bbf7d0" if is_dark else "#ffffff"
        btn_hover = "#15803d" if is_dark else "#16a34a"

        self.setStyleSheet(f"""
            QFrame#FeatureSuggestionCard {{
                border: 1.5px solid {accent_green};
                border-radius: 12px;
                background-color: {bg_green_dark};
            }}
            QLabel#CardTitle   {{ color: {accent_green}; font-weight: bold; font-size: 13px; }}
            QLabel#PathLabel   {{ color: {_c.get("text_hint", "#6b7280")}; font-size: 10px; }}
            QFrame#SuggItem    {{
                border: 1px solid {border_green};
                border-radius: 8px;
                background-color: {bg_green_item};
            }}
            QLabel#SuggTitle   {{ color: {title_green}; font-weight: bold; font-size: 12px; }}
            QLabel#SuggDesc    {{ color: {desc_green}; font-size: 11px; }}
            QLabel#SuggWhy     {{ color: {_c.get("text_hint", "#6b7280")}; font-size: 10px; font-style: italic; }}
            QPushButton#AddBtn {{
                background-color: {btn_bg};
                color: {btn_fg};
                border: none;
                border-radius: 6px;
                padding: 4px 12px;
                font-size: 11px;
            }}
            QPushButton#AddBtn:hover {{ background-color: {btn_hover}; }}
            QPushButton#AddBtn:disabled {{
                background-color: #1c3a2a;
                color: #4b7a5e;
            }}
            QPushButton#AddBtnDone {{
                background-color: #064e3b;
                color: #6ee7b7;
                border: 1px solid #059669;
                border-radius: 6px;
                padding: 4px 12px;
                font-size: 11px;
            }}
            QPushButton#AddBtnQueued {{
                background-color: {_c.get("bg_raised", "#1e3a5f")};
                color: {_c.get("text_secondary", "#93c5fd")};
                border: 1px solid {_c.get("accent_primary", "#3b82f6")};
                border-radius: 6px;
                padding: 4px 12px;
                font-size: 11px;
            }}
        """)

        layout = QVBoxLayout(self)
        layout.setContentsMargins(14, 10, 14, 12)
        layout.setSpacing(10)

        # ── 헤더 ──────────────────────────────────────────────────
        header = QHBoxLayout()
        title = QLabel(tr("feature_sug_title"))
        title.setObjectName("CardTitle")
        header.addWidget(title)
        header.addStretch()
        fname_label = QLabel(os.path.basename(file_path))
        fname_label.setObjectName("PathLabel")
        header.addWidget(fname_label)
        layout.addLayout(header)

        # ── 제안 아이템들 ──────────────────────────────────────────
        if not suggestions:
            empty = QLabel(tr("feature_sug_empty"))
            empty.setObjectName("SuggDesc")
            layout.addWidget(empty)
        else:
            for i, s in enumerate(suggestions):
                layout.addWidget(self._make_item(i, s))

    def _make_item(self, idx: int, s: dict) -> QFrame:
        item = QFrame()
        item.setObjectName("SuggItem")
        v = QVBoxLayout(item)
        v.setContentsMargins(12, 8, 12, 8)
        v.setSpacing(4)

        # 제목 + 버튼 행
        top = QHBoxLayout()
        num = QLabel(f"{idx + 1}. {s.get('title', tr('lbl_feature_default'))}")
        num.setObjectName("SuggTitle")
        top.addWidget(num)
        top.addStretch()

        add_btn = QPushButton(tr("btn_add_feature"))
        add_btn.setObjectName("AddBtn")
        add_btn.setCursor(Qt.PointingHandCursor)
        add_btn.clicked.connect(lambda _, suggestion=s, btn=add_btn: self._on_add_btn_clicked(suggestion, btn))
        top.addWidget(add_btn)
        v.addLayout(top)

        # 버튼 레퍼런스 저장 (title 키로)
        self._btn_map[s.get("title", f"_{idx}")] = add_btn

        # 설명
        desc = QLabel(s.get("description", ""))
        desc.setObjectName("SuggDesc")
        desc.setWordWrap(True)
        v.addWidget(desc)

        # 왜 유용한가
        why_text = s.get("why", "")
        if why_text:
            why = QLabel(f"→ {why_text}")
            why.setObjectName("SuggWhy")
            why.setWordWrap(True)
            v.addWidget(why)

        return item

    def _on_add_btn_clicked(self, suggestion: dict, btn: QPushButton):
        """버튼 클릭 → 큐에 추가, 버튼을 '대기 중' 상태로 전환"""
        # 이미 대기열에 있거나 처리 완료된 버튼이면 무시
        if not btn.isEnabled():
            return
        btn.setText(tr("btn_feature_waiting"))
        btn.setObjectName("AddBtnQueued")
        btn.setEnabled(False)
        btn.setStyleSheet("")  # QSS 재적용 트리거
        btn.style().unpolish(btn)
        btn.style().polish(btn)
        self._request_queue.append((suggestion, btn))
        if not self._processing:
            self._process_next()

    def _process_next(self):
        """큐에서 다음 요청을 꺼내 처리"""
        if not self._request_queue:
            self._processing = False
            return
        self._processing = True
        suggestion, btn = self._request_queue.pop(0)

        # 버튼 상태: 처리 중
        btn.setText(tr("btn_feature_adding"))
        btn.setObjectName("AddBtn")
        btn.setEnabled(False)
        btn.style().unpolish(btn)
        btn.style().polish(btn)

        title = suggestion.get("title", "기능")
        description = suggestion.get("description", "")
        instruction = (
            f"다음 기능을 코드에 추가해주세요: {title}\n"
            f"상세 내용: {description}\n\n"
            f"[주의] 기존 코드 구조를 최대한 유지하고, 새 기능만 핀셋으로 추가하세요."
        )
        self.chat_window.append_message(f"➕ '{title}' 추가 요청", "user")
        # 완료 콜백을 전달하여 처리 완료 시 다음 큐 항목 자동 실행
        self.chat_window._handle_code_fix_request(
            [self.file_path], instruction,
            on_done=lambda: self._on_feature_done(btn)
        )

    def _on_feature_done(self, btn: QPushButton):
        """단일 기능 추가 완료 → 버튼 '완료' 상태, 다음 큐 처리"""
        btn.setText(tr("btn_feature_done"))
        btn.setObjectName("AddBtnDone")
        btn.setEnabled(False)
        btn.style().unpolish(btn)
        btn.style().polish(btn)
        self._processing = False
        self._process_next()

    def _request_add_feature(self, suggestion: dict):
        """하위 호환용 — 직접 호출 시 큐 경로로 리다이렉트"""
        key = suggestion.get("title", "")
        btn = self._btn_map.get(key)
        if btn:
            self._on_add_btn_clicked(suggestion, btn)


# ═══════════════════════════════════════════════════════════════════════════
# 🏗️ AppBuilder 카드 — 체크리스트 / 목업 미리보기 / 스캐폴딩 결과
# ═══════════════════════════════════════════════════════════════════════════

def _scaffold_card_palette():
    """현재 테마에 맞춘 스캐폴딩 카드 색상 팔레트.
    카드 표면·테두리·텍스트는 테마를 따르고, 단계별 accent 는
    각 카드가 자기 색(indigo/blue/green)으로 유지해 시각 차별화."""
    try:
        _name = load_theme_setting()
        _theme = THEMES.get(_name, THEMES["Modern Dark"])
    except Exception:
        _theme = THEMES["Modern Dark"]
    _c = _theme.get("colors", {})
    return {
        "is_dark": bool(_theme.get("is_dark", False)),
        "card_bg":      _c.get("bg_raised", "#ffffff"),
        "row_bg":       _c.get("bg_surface", "#f8fafc"),
        "input_bg":     _c.get("bg_input", "#f8fafc"),
        "border":       _c.get("border_subtle", "#e2e8f0"),
        "divider":      _c.get("border_subtle", "#e2e8f0"),
        "text_title":   _c.get("text_title", "#1e293b"),
        "text_sub":     _c.get("text_secondary", "#64748b"),
        "text_primary": _c.get("text_primary", "#334155"),
        "text_hint":    _c.get("text_hint", "#94a3b8"),
        "danger_bg":    _c.get("danger_bg", "#dc2626"),
        "danger_text":  _c.get("danger_text", "#ffffff"),
    }


class AppRequirementsCard(QFrame):
    """
    [Step 1] 앱 제작 요구사항 체크리스트 인라인 카드.
    테마 적응형 (Modern Dark/Tokyo Night/Latte 등 자동 추종).
    """
    submitted = Signal(dict)

    @staticmethod
    def _build_style() -> str:
        p = _scaffold_card_palette()
        # step 1 accent — indigo (다크에선 약간 더 밝게)
        accent       = "#818cf8" if p["is_dark"] else "#6366f1"
        accent_hover = "#a5b4fc" if p["is_dark"] else "#4f52e9"
        accent_soft  = "rgba(99,102,241,0.18)" if p["is_dark"] else "#eef2ff"
        accent_disabled = "#3730a3" if p["is_dark"] else "#c7d2fe"
        return f"""
        QFrame#AppRequirementsCard {{
            background: {p['card_bg']};
            border: 1.5px solid {accent_soft};
            border-radius: 16px;
        }}
        QLabel#cardBadge {{
            background: {accent_soft};
            color: {accent};
            border-radius: 10px;
            padding: 2px 10px;
            font-size: 8pt;
            font-weight: bold;
        }}
        QLabel#cardTitle {{
            color: {p['text_title']};
            font-size: 13pt;
            font-weight: bold;
        }}
        QLabel#cardSub {{ color: {p['text_sub']}; font-size: 9pt; }}
        QLabel#itemLabel {{
            color: {p['text_primary']};
            font-size: 9pt;
            font-weight: bold;
        }}
        QLabel#typeHint {{ color: {p['text_hint']}; font-size: 8pt; }}
        QPushButton#optionBtn {{
            background: {p['row_bg']};
            color: {p['text_primary']};
            border: 1.5px solid {p['border']};
            border-radius: 20px;
            padding: 4px 14px;
            font-size: 9pt;
        }}
        QPushButton#optionBtn:hover {{
            border-color: {accent};
            color: {accent};
            background: {accent_soft};
        }}
        QPushButton#optionBtn:checked {{
            background: {accent};
            color: #ffffff;
            border-color: {accent};
            font-weight: bold;
        }}
        QPushButton#submitBtn {{
            background: {accent};
            color: white;
            border-radius: 10px;
            padding: 9px 28px;
            font-size: 10pt;
            font-weight: bold;
            border: none;
        }}
        QPushButton#submitBtn:hover {{ background: {accent_hover}; }}
        QPushButton#submitBtn:disabled {{ background: {accent_disabled}; color: {accent_soft}; }}
        QLineEdit#textInput {{
            background: {p['input_bg']};
            color: {p['text_primary']};
            border: 1.5px solid {p['border']};
            border-radius: 8px;
            padding: 6px 12px;
            font-size: 9pt;
        }}
        QLineEdit#textInput:focus {{ border-color: {accent}; background: {p['card_bg']}; }}
        """

    def __init__(self, checklist: dict, parent_chat_window=None):
        super().__init__()
        self.setObjectName("AppRequirementsCard")
        self._palette = _scaffold_card_palette()
        self.setStyleSheet(self._build_style())
        self._chat = parent_chat_window
        self._items = checklist.get("items", [])
        self._project_type = checklist.get("project_type", "앱")
        self._selections: dict = {}
        self._texts: dict = {}
        self._btn_groups: dict = {}
        self._build_ui()

    def _build_ui(self):
        outer = QVBoxLayout(self)
        outer.setContentsMargins(24, 20, 24, 20)
        outer.setSpacing(0)

        # 헤더
        hdr = QHBoxLayout(); hdr.setSpacing(10)
        badge = QLabel("STEP 1")
        badge.setObjectName("cardBadge")
        badge.setFixedHeight(22)
        hdr.addWidget(badge, 0, Qt.AlignVCenter)
        title = QLabel(f"{self._project_type} 요구사항 파악")
        title.setObjectName("cardTitle")
        hdr.addWidget(title, 0, Qt.AlignVCenter)
        hdr.addStretch()
        outer.addLayout(hdr)

        outer.addSpacing(4)
        sub = QLabel("아래 항목을 작성하면 EIDOS가 UI 목업을 생성합니다.")
        sub.setObjectName("cardSub")
        outer.addWidget(sub)
        outer.addSpacing(16)

        div = QFrame()
        div.setFixedHeight(1)
        div.setStyleSheet(f"background:{self._palette['divider']};")
        outer.addWidget(div)
        outer.addSpacing(14)

        # 항목 목록
        items_layout = QVBoxLayout()
        items_layout.setSpacing(8)

        for idx, item in enumerate(self._items):
            iid   = item.get("id", f"item_{idx}")
            label = item.get("label", "")
            itype = item.get("type", "text")
            opts  = item.get("options", [])
            ph    = item.get("placeholder", "")

            row_frame = QFrame()
            row_frame.setStyleSheet(
                f"QFrame {{ background:{self._palette['row_bg']}; border-radius:10px;"
                f" border:1px solid {self._palette['border']}; }}"
            )
            row_lay = QVBoxLayout(row_frame)
            row_lay.setContentsMargins(14, 10, 14, 10)
            row_lay.setSpacing(6)

            lbl_row = QHBoxLayout()
            lbl = QLabel(label); lbl.setObjectName("itemLabel")
            lbl_row.addWidget(lbl)
            type_map = {"single_select":"단일 선택","multi_select":"복수 선택","text":"직접 입력"}
            hint = QLabel(type_map.get(itype, "")); hint.setObjectName("typeHint")
            lbl_row.addWidget(hint)
            lbl_row.addStretch()
            row_lay.addLayout(lbl_row)

            if itype in ("single_select", "multi_select"):
                btn_wrap = QWidget()
                btn_wrap.setStyleSheet("background:transparent;border:none;")
                btn_lay = QHBoxLayout(btn_wrap)
                btn_lay.setContentsMargins(0,0,0,0); btn_lay.setSpacing(6)
                self._btn_groups[iid] = []
                self._selections[iid] = []
                for opt in opts:
                    btn = QPushButton(opt)
                    btn.setObjectName("optionBtn")
                    btn.setCheckable(True)
                    btn.setCursor(Qt.PointingHandCursor)
                    btn.clicked.connect(lambda checked, i=iid, o=opt, t=itype, b=btn:
                                        self._on_option_click(i, o, t, b))
                    btn_lay.addWidget(btn)
                    self._btn_groups[iid].append(btn)
                btn_lay.addStretch()
                row_lay.addWidget(btn_wrap)
            else:
                le = QLineEdit()
                le.setObjectName("textInput")
                le.setPlaceholderText(ph or f"{label}을 입력하세요")
                self._texts[iid] = le
                row_lay.addWidget(le)

            items_layout.addWidget(row_frame)

        outer.addLayout(items_layout)
        outer.addSpacing(18)

        btn_row = QHBoxLayout()
        btn_row.addStretch()
        self._submit_btn = QPushButton("✦  UI 목업 생성하기")
        self._submit_btn.setObjectName("submitBtn")
        self._submit_btn.setCursor(Qt.PointingHandCursor)
        self._submit_btn.setFixedHeight(38)
        self._submit_btn.clicked.connect(self._on_submit)
        btn_row.addWidget(self._submit_btn)
        outer.addLayout(btn_row)

    def _on_option_click(self, iid: str, opt: str, itype: str, btn: QPushButton):
        if itype == "single_select":
            for b in self._btn_groups.get(iid, []):
                if b is not btn:
                    b.setChecked(False)
            self._selections[iid] = [opt] if btn.isChecked() else []
        else:
            sel = self._selections.setdefault(iid, [])
            if btn.isChecked():
                if opt not in sel: sel.append(opt)
            else:
                if opt in sel: sel.remove(opt)

    def _on_submit(self):
        answers = {}
        for iid, sel in self._selections.items():
            answers[iid] = sel[0] if len(sel) == 1 else sel
        for iid, le in self._texts.items():
            answers[iid] = le.text().strip()
        labeled = {}
        for item in self._items:
            iid = item.get("id", "")
            labeled[item.get("label", iid)] = answers.get(iid, "")
        labeled["__project_type__"] = self._project_type
        self._submit_btn.setText("⏳ 목업 생성 중...")
        self._submit_btn.setEnabled(False)
        self.setEnabled(False)
        self.submitted.emit(labeled)


# ─────────────────────────────────────────────────────────────────────────────

class MockupPreviewCard(QFrame):
    """
    [Step 2] UI 스키마 기반 HTML 목업 미리보기 카드.
    테마 적응형.
    """
    confirmed      = Signal(dict)
    edit_requested = Signal(str, dict)

    @staticmethod
    def _build_style() -> str:
        p = _scaffold_card_palette()
        # step 2 accent — blue
        accent       = "#60a5fa" if p["is_dark"] else "#3b82f6"
        accent_hover = "#3b82f6" if p["is_dark"] else "#2563eb"
        accent_soft  = "rgba(59,130,246,0.18)" if p["is_dark"] else "#eff6ff"
        accent_disabled = "#1e40af" if p["is_dark"] else "#bfdbfe"
        return f"""
        QFrame#MockupPreviewCard {{
            background: {p['card_bg']};
            border: 1.5px solid {accent_soft};
            border-radius: 16px;
        }}
        QLabel#cardBadge {{
            background: {accent_soft};
            color: {accent};
            border-radius: 10px;
            padding: 2px 10px;
            font-size: 8pt;
            font-weight: bold;
        }}
        QLabel#cardTitle {{ color: {p['text_title']}; font-size: 13pt; font-weight: bold; }}
        QLabel#cardSub   {{ color: {p['text_sub']}; font-size: 9pt; }}
        QPushButton#confirmBtn {{
            background: {accent}; color: white;
            border-radius: 10px; padding: 9px 24px;
            font-size: 10pt; font-weight: bold; border: none;
        }}
        QPushButton#confirmBtn:hover   {{ background: {accent_hover}; }}
        QPushButton#confirmBtn:disabled {{ background: {accent_disabled}; color: {accent_soft}; }}
        QPushButton#editBtn {{
            background: {p['row_bg']}; color: {p['text_primary']};
            border-radius: 8px; padding: 7px 16px;
            font-size: 9pt; border: 1.5px solid {p['border']};
        }}
        QPushButton#editBtn:hover {{ background: {accent_soft}; color: {accent}; }}
        QLineEdit#editInput {{
            background: {p['input_bg']}; color: {p['text_primary']};
            border: 1.5px solid {p['border']}; border-radius: 8px;
            padding: 6px 12px; font-size: 9pt;
        }}
        QLineEdit#editInput:focus {{ border-color: {accent}; }}
        """

    def __init__(self, ui_schema: dict, html: str, parent_chat_window=None):
        super().__init__()
        self.setObjectName("MockupPreviewCard")
        self._palette = _scaffold_card_palette()
        self.setStyleSheet(self._build_style())
        self._schema = ui_schema
        self._chat   = parent_chat_window
        self._build_ui(html)

    def _build_ui(self, html: str):
        outer = QVBoxLayout(self)
        outer.setContentsMargins(24, 20, 24, 20)
        outer.setSpacing(0)

        # 헤더
        hdr = QHBoxLayout(); hdr.setSpacing(10)
        badge = QLabel("STEP 2"); badge.setObjectName("cardBadge"); badge.setFixedHeight(22)
        hdr.addWidget(badge, 0, Qt.AlignVCenter)
        # [Phase 1-a] HTML 목업 제거 — 스키마 확정 카드로 역할 변경
        _skip_html = not (html or "").strip()
        _title_text = "UI 스키마 확인" if _skip_html else "UI 목업 미리보기"
        title = QLabel(_title_text); title.setObjectName("cardTitle")
        hdr.addWidget(title, 0, Qt.AlignVCenter)
        hdr.addStretch()
        outer.addLayout(hdr)

        outer.addSpacing(4)
        _sub_text = (
            "HTML 목업 단계 생략 — 확정하면 DNA 기반으로 바로 스캐폴딩합니다."
            if _skip_html else
            "마음에 들지 않는 부분을 입력하면 즉시 수정합니다."
        )
        sub = QLabel(_sub_text)
        sub.setObjectName("cardSub")
        outer.addWidget(sub)
        outer.addSpacing(14)

        div = QFrame(); div.setFixedHeight(1)
        div.setStyleSheet(f"background:{self._palette['divider']};")
        outer.addWidget(div)
        outer.addSpacing(12)

        if _skip_html:
            # 스키마 요약 텍스트 라벨
            import json as _json_sk
            try:
                _sch_preview = _json_sk.dumps(
                    self._schema, ensure_ascii=False, indent=2
                )[:1200]
            except Exception:
                _sch_preview = str(self._schema)[:1200]
            schema_view = QLabel(_sch_preview)
            schema_view.setStyleSheet(
                f"background:{self._palette['row_bg']}; color:{self._palette['text_primary']};"
                f" border-radius:10px; border:1px solid {self._palette['border']};"
                f" padding:14px; font-family:'Consolas','맑은 고딕',monospace;"
                f" font-size:9pt;"
            )
            schema_view.setWordWrap(True)
            schema_view.setTextInteractionFlags(Qt.TextSelectableByMouse)
            outer.addWidget(schema_view)
            self._webview = None
        elif WEB_ENGINE_LOADED:
            self._webview = QWebEngineView()
            self._webview.setFixedHeight(420)
            self._webview.setStyleSheet("border-radius:10px;")
            self._webview.setHtml(html)
            outer.addWidget(self._webview)
        else:
            _err_bg = "rgba(239,68,68,0.18)" if self._palette["is_dark"] else "#fff1f2"
            fallback = QLabel("⚠️ WebEngine 미설치 — HTML 목업을 표시할 수 없습니다")
            fallback.setStyleSheet(
                f"color:#ef4444; background:{_err_bg}; border-radius:8px;"
                f" padding:40px; font-size:10pt;"
            )
            fallback.setAlignment(Qt.AlignCenter)
            outer.addWidget(fallback)
            self._webview = None

        outer.addSpacing(12)

        # 수정 요청 행
        edit_row = QHBoxLayout(); edit_row.setSpacing(8)
        self._edit_input = QLineEdit()
        self._edit_input.setObjectName("editInput")
        self._edit_input.setPlaceholderText("예: 사이드바 제거, 버튼 색상을 초록으로, 다크 테마로...")
        self._edit_input.setFixedHeight(36)
        self._edit_input.returnPressed.connect(self._on_edit)
        edit_row.addWidget(self._edit_input)

        edit_btn = QPushButton("↺  수정")
        edit_btn.setObjectName("editBtn")
        edit_btn.setCursor(Qt.PointingHandCursor)
        edit_btn.setFixedHeight(36)
        edit_btn.clicked.connect(self._on_edit)
        edit_row.addWidget(edit_btn)
        outer.addLayout(edit_row)
        outer.addSpacing(10)

        # 확정 버튼
        btn_row = QHBoxLayout(); btn_row.addStretch()
        self._confirm_btn = QPushButton("✦  이 디자인으로 개발 시작")
        self._confirm_btn.setObjectName("confirmBtn")
        self._confirm_btn.setCursor(Qt.PointingHandCursor)
        self._confirm_btn.setFixedHeight(38)
        self._confirm_btn.clicked.connect(self._on_confirm)
        btn_row.addWidget(self._confirm_btn)
        outer.addLayout(btn_row)

    def update_html(self, html: str):
        if self._webview:
            self._webview.setHtml(html)

    def update_schema(self, new_schema: dict):
        self._schema = new_schema

    def _on_edit(self):
        req = self._edit_input.text().strip()
        if not req: return
        self._edit_input.clear()
        self._edit_input.setPlaceholderText("⏳ 수정 중...")
        self._edit_input.setEnabled(False)
        self.edit_requested.emit(req, self._schema)

    def unlock_edit(self):
        self._edit_input.setEnabled(True)
        self._edit_input.setPlaceholderText("예: 사이드바 제거, 버튼 색상을 초록으로, 다크 테마로...")

    def _on_confirm(self):
        self._confirm_btn.setText("⏳ 코드 생성 중...")
        self._confirm_btn.setEnabled(False)
        self.confirmed.emit(self._schema)


# ─────────────────────────────────────────────────────────────────────────────

class ScaffoldResultCard(QFrame):
    """
    [Step 3] 스캐폴딩 완료 카드. 테마 적응형.
    - 진입점 파일 빨간 강조 + 미리보기 실행 버튼
    - 실행 후 stderr 캐치 → EIDOS에 자동 전달하여 코드 수정 요청
    """
    # 백그라운드 스레드 → GUI 스레드 크래시 브리지
    _crash_detected = Signal(str)

    @staticmethod
    def _build_style() -> str:
        p = _scaffold_card_palette()
        # step 3 accent — green
        accent       = "#4ade80" if p["is_dark"] else "#16a34a"
        accent_hover = "#22c55e" if p["is_dark"] else "#15803d"
        accent_soft  = "rgba(34,197,94,0.18)" if p["is_dark"] else "#f0fdf4"
        accent_disabled = "#166534" if p["is_dark"] else "#86efac"
        # entry 강조색 — 다크에선 기존 빨강이 너무 튀지 않게 약간 톤다운
        entry_color = "#fca5a5" if p["is_dark"] else "#dc2626"
        err_bg = "rgba(239,68,68,0.18)" if p["is_dark"] else "#fef2f2"
        return f"""
        QFrame#ScaffoldResultCard {{
            background: {p['card_bg']};
            border: 1.5px solid {accent_soft};
            border-radius: 16px;
        }}
        QLabel#cardBadge {{
            background: {accent_soft};
            color: {accent};
            border-radius: 10px;
            padding: 2px 10px;
            font-size: 8pt;
            font-weight: bold;
        }}
        QLabel#cardTitle {{ color: {p['text_title']}; font-size: 13pt; font-weight: bold; }}
        QLabel#fileItem  {{
            color: {p['text_primary']}; font-size: 9pt;
            font-family: Consolas, monospace; padding: 2px 0;
        }}
        QLabel#entryItem {{
            color: {entry_color}; font-size: 9pt;
            font-family: Consolas, monospace;
            font-weight: bold; padding: 2px 0;
        }}
        QPushButton#runBtn {{
            background: {accent}; color: white;
            border-radius: 10px; padding: 9px 24px;
            font-size: 10pt; font-weight: bold; border: none;
        }}
        QPushButton#runBtn:hover {{ background: {accent_hover}; }}
        QPushButton#runBtn:disabled {{ background: {accent_disabled}; }}
        QLabel#guideMsg {{ color: {p['text_sub']}; font-size: 9pt; font-style: italic; }}
        QLabel#errorMsg {{
            color: {entry_color}; font-size: 9pt;
            background: {err_bg}; border-radius: 6px; padding: 6px 10px;
        }}
        """

    def __init__(self, scaffold_result: dict, project_base_dir: str,
                 parent_chat_window=None, eidos_worker=None):
        super().__init__()
        self.setObjectName("ScaffoldResultCard")
        self._palette = _scaffold_card_palette()
        self.setStyleSheet(self._build_style())
        self._result        = scaffold_result
        self._base_dir      = project_base_dir
        self._chat          = parent_chat_window
        self._worker        = eidos_worker
        self._proc_thread   = None   # stderr 모니터 스레드
        self._autofix_count = 0      # 자동 수정 호출 횟수 (무한루프 방지)
        self._AUTOFIX_MAX   = 3      # 최대 자동 수정 횟수
        # 백그라운드 스레드 → GUI 스레드 브리지: 크래시 감지 시 GUI 스레드에서 수정 루프 시작
        self._crash_detected.connect(self._send_error_to_eidos)
        self._build_ui()

    def _build_ui(self):
        outer = QVBoxLayout(self)
        outer.setContentsMargins(24, 20, 24, 20)
        outer.setSpacing(0)

        # 헤더
        hdr = QHBoxLayout(); hdr.setSpacing(10)
        badge = QLabel("STEP 3"); badge.setObjectName("cardBadge"); badge.setFixedHeight(22)
        hdr.addWidget(badge, 0, Qt.AlignVCenter)
        title = QLabel("프로젝트 생성 완료"); title.setObjectName("cardTitle")
        hdr.addWidget(title, 0, Qt.AlignVCenter)
        hdr.addStretch()
        outer.addLayout(hdr)
        outer.addSpacing(14)

        div = QFrame(); div.setFixedHeight(1)
        div.setStyleSheet(f"background:{self._palette['divider']};")
        outer.addWidget(div)
        outer.addSpacing(12)

        # DC summary 안의 정보색은 step2(파랑) 톤을 따라간다 — 다크/라이트 자동
        _dc_accent = "#60a5fa" if self._palette["is_dark"] else "#1d4ed8"
        _dc_text   = "#93c5fd" if self._palette["is_dark"] else "#1e40af"
        _dc_bg     = "rgba(59,130,246,0.15)" if self._palette["is_dark"] else "#eff6ff"
        _dc_border = "rgba(59,130,246,0.35)" if self._palette["is_dark"] else "#bfdbfe"
        _risk_color = "#fca5a5" if self._palette["is_dark"] else "#dc2626"

        # ── DCReasoner 분석 요약 (있을 때만 표시) ──────────────────────
        dc_summary = self._result.get("_dc_summary", {})
        if dc_summary:
            dc_box = QFrame()
            dc_box.setStyleSheet(
                f"QFrame {{ background:{_dc_bg}; border-radius:10px; border:1px solid {_dc_border}; }}"
            )
            dc_lay = QVBoxLayout(dc_box)
            dc_lay.setContentsMargins(14, 10, 14, 10)
            dc_lay.setSpacing(4)

            dc_title = QLabel("🧠 DCReasoner 분석 결과")
            dc_title.setStyleSheet(f"color:{_dc_accent}; font-size:9pt; font-weight:bold;")
            dc_lay.addWidget(dc_title)

            def _dc_to_str(x):
                if isinstance(x, str):
                    return x
                if isinstance(x, dict):
                    for k in ("name", "title", "feature", "step", "risk", "desc", "description"):
                        v = x.get(k)
                        if isinstance(v, str) and v.strip():
                            return v
                    return json.dumps(x, ensure_ascii=False)
                return str(x)

            features = dc_summary.get("features", [])
            if features:
                feat_lbl = QLabel("기능: " + " · ".join(_dc_to_str(f) for f in features[:6]))
                feat_lbl.setStyleSheet(f"color:{_dc_text}; font-size:8pt;")
                feat_lbl.setWordWrap(True)
                dc_lay.addWidget(feat_lbl)

            impl_order = dc_summary.get("impl_order", [])
            if impl_order:
                order_lbl = QLabel("구현 순서: " + " → ".join(_dc_to_str(s) for s in impl_order))
                order_lbl.setStyleSheet(f"color:{_dc_text}; font-size:8pt;")
                order_lbl.setWordWrap(True)
                dc_lay.addWidget(order_lbl)

            risks = dc_summary.get("risk_factors", [])
            if risks:
                risk_lbl = QLabel("⚠ " + _dc_to_str(risks[0]))
                risk_lbl.setStyleSheet(f"color:{_risk_color}; font-size:8pt;")
                risk_lbl.setWordWrap(True)
                dc_lay.addWidget(risk_lbl)

            outer.addWidget(dc_box)
            outer.addSpacing(10)

        # 파일 목록
        files    = self._result.get("files", {})
        entry    = self._result.get("entry_file", "main.py")
        proj_dir = self._result.get("project_dir", "project")

        file_box = QFrame()
        file_box.setStyleSheet(
            f"QFrame {{ background:{self._palette['row_bg']}; border-radius:10px; border:1px solid {self._palette['border']}; }}"
        )
        file_lay = QVBoxLayout(file_box)
        file_lay.setContentsMargins(14, 10, 14, 10)
        file_lay.setSpacing(2)

        _entry_dot = "#fca5a5" if self._palette["is_dark"] else "#dc2626"
        for rel_path in files.keys():
            is_entry = (rel_path == entry)
            row = QHBoxLayout(); row.setSpacing(8)
            dot = QLabel("●")
            dot.setStyleSheet(f"color:{_entry_dot if is_entry else self._palette['text_hint']}; font-size:7pt;")
            row.addWidget(dot, 0, Qt.AlignVCenter)
            lbl = QLabel(rel_path + ("  ← 진입점" if is_entry else ""))
            lbl.setObjectName("entryItem" if is_entry else "fileItem")
            row.addWidget(lbl)
            row.addStretch()
            file_lay.addLayout(row)

        outer.addWidget(file_box)
        outer.addSpacing(14)

        # 실행 버튼
        btn_row = QHBoxLayout()
        self._entry_path = os.path.join(self._base_dir, proj_dir, entry)
        self._run_btn = QPushButton(f"▶  미리보기 실행   ({entry})")
        self._run_btn.setObjectName("runBtn")
        self._run_btn.setCursor(Qt.PointingHandCursor)
        self._run_btn.setFixedHeight(38)
        self._run_btn.clicked.connect(self._run_entry)
        btn_row.addWidget(self._run_btn)
        btn_row.addStretch()
        outer.addLayout(btn_row)
        outer.addSpacing(10)

        # 오류 표시 영역 (초기 숨김)
        self._error_lbl = QLabel()
        self._error_lbl.setObjectName("errorMsg")
        self._error_lbl.setWordWrap(True)
        self._error_lbl.setVisible(False)
        outer.addWidget(self._error_lbl)

        guide = QLabel("오류가 발생하면 EIDOS가 자동으로 분석하고 수정합니다. 🤖")
        guide.setObjectName("guideMsg")
        guide.setWordWrap(True)
        outer.addWidget(guide)

        # ── AutoFix 실시간 로그 패널 (초기 숨김) ───────────────────
        self._autofix_panel = QFrame()
        self._autofix_panel.setStyleSheet(
            "QFrame { background:#0f172a; border-radius:10px; border:1px solid #334155; }"
        )
        self._autofix_panel.setVisible(False)
        af_lay = QVBoxLayout(self._autofix_panel)
        af_lay.setContentsMargins(12, 8, 12, 8)
        af_lay.setSpacing(4)

        af_title_row = QHBoxLayout()
        af_title = QLabel("🤖 AutoFix 루프 실행 중")
        af_title.setStyleSheet("color:#38bdf8; font-size:9pt; font-weight:bold;")
        af_title_row.addWidget(af_title)
        af_title_row.addStretch()
        self._autofix_attempt_lbl = QLabel("")
        self._autofix_attempt_lbl.setStyleSheet("color:#64748b; font-size:8pt;")
        af_title_row.addWidget(self._autofix_attempt_lbl)
        af_lay.addLayout(af_title_row)

        from PySide6.QtWidgets import QTextEdit as _QTE
        self._autofix_log = _QTE()
        self._autofix_log.setReadOnly(True)
        self._autofix_log.setFixedHeight(160)
        self._autofix_log.setStyleSheet(
            "QTextEdit { background:#0f172a; color:#94a3b8; "
            "font-family: Consolas, monospace; font-size:8pt; "
            "border:none; }"
        )
        af_lay.addWidget(self._autofix_log)

        # 진행바
        from PySide6.QtWidgets import QProgressBar as _QPB
        self._autofix_progress = _QPB()
        self._autofix_progress.setRange(0, 0)  # 인디케이터 모드
        self._autofix_progress.setFixedHeight(4)
        self._autofix_progress.setStyleSheet(
            "QProgressBar { background:#1e293b; border:none; border-radius:2px; }"
            "QProgressBar::chunk { background:#38bdf8; border-radius:2px; }"
        )
        af_lay.addWidget(self._autofix_progress)
        outer.addSpacing(8)
        outer.addWidget(self._autofix_panel)

    def append_autofix_log(self, msg: str):
        """AutoFix 로그 패널에 메시지 추가 (thread-safe via QTimer)."""
        def _do():
            try:
                # 패널 표시
                if not self._autofix_panel.isVisible():
                    self._autofix_panel.setVisible(True)

                # attempt 번호 파싱
                import re as _re
                m = _re.search(r"AutoFix (\d+)/(\d+)", msg)
                if m:
                    self._autofix_attempt_lbl.setText(f"시도 {m.group(1)}/{m.group(2)}")

                # 색상 맵핑
                if "✅" in msg:
                    color = "#4ade80"  # 초록
                    self._autofix_progress.setRange(0, 1)
                    self._autofix_progress.setValue(1)
                    self._autofix_attempt_lbl.setText("완료 ✅")
                    self._autofix_attempt_lbl.setStyleSheet("color:#4ade80; font-size:8pt;")
                elif "❌" in msg:
                    color = "#f87171"  # 빨강
                    self._autofix_progress.setRange(0, 1)
                    self._autofix_progress.setValue(0)
                    self._autofix_attempt_lbl.setText("실패 ❌")
                    self._autofix_attempt_lbl.setStyleSheet("color:#f87171; font-size:8pt;")
                elif "🔄" in msg:
                    color = "#fb923c"  # 주황
                elif "📍" in msg or "💾" in msg:
                    color = "#a78bfa"  # 보라
                elif "▶" in msg:
                    color = "#38bdf8"  # 하늘
                else:
                    color = "#94a3b8"  # 회색

                # HTML 로그 추가
                safe_msg = msg.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
                self._autofix_log.append(
                    f'<span style="color:{color};">{safe_msg}</span>'
                )
                # 스크롤 최하단
                sb = self._autofix_log.verticalScrollBar()
                sb.setValue(sb.maximum())
            except RuntimeError:
                pass
        QTimer.singleShot(0, _do)

    def _run_entry(self):
        if not os.path.exists(self._entry_path):
            self._show_error(f"진입점 파일을 찾을 수 없습니다:\n{self._entry_path}")
            return
        try:
            self._run_btn.setText("⏳ 실행 중...")
            self._run_btn.setEnabled(False)
            self._error_lbl.setVisible(False)

            # stdout=DEVNULL: Windows에서 stdout=PIPE면 PySide6 GUI 창이 안 뜨는 문제 있음.
            # stderr만 PIPE로 잡아서 오류 캡처.
            # [Fix 2026-04-25] PYTHONIOENCODING=utf-8 + PYTHONUTF8=1 — 자식이
            # cp949 로 traceback 을 출력해 부모가 utf-8 로 읽으면 한글 폴더명이
            # ��_��_����_�� 로 깨지던 문제 해결. 파이썬 -X utf8 모드와 동등.
            _child_env = os.environ.copy()
            _child_env["PYTHONIOENCODING"] = "utf-8"
            _child_env["PYTHONUTF8"] = "1"
            proc = subprocess.Popen(
                [sys.executable, self._entry_path],
                cwd=os.path.dirname(self._entry_path),
                stderr=subprocess.PIPE,
                stdout=subprocess.DEVNULL,
                text=True,
                encoding="utf-8",
                errors="replace",
                env=_child_env,
            )
            if self._chat:
                self._chat.append_message(
                    f"▶ 앱 실행 중: {os.path.basename(self._entry_path)}", "system"
                )

            # 백그라운드 스레드로 프로세스 감시
            self._proc_thread = threading.Thread(
                target=self._monitor_proc, args=(proc,), daemon=True
            )
            self._proc_thread.start()

            # 버튼 복구 (6초 후 — 크래시 감지 타임아웃 5초 이후)
            QTimer.singleShot(6000, lambda: (
                self._run_btn.setText(
                    f"▶  재실행   ({os.path.basename(self._entry_path)})"
                ),
                self._run_btn.setEnabled(True),
            ))

        except Exception as e:
            self._show_error(str(e))
            self._run_btn.setText(f"▶  미리보기 실행   ({os.path.basename(self._entry_path)})")
            self._run_btn.setEnabled(True)

    def _monitor_proc(self, proc: subprocess.Popen):
        """백그라운드 프로세스 감시.

        5초 안에 종료 → 크래시 확정 → stderr 수집 → _show_error + _send_error_to_eidos.
        5초 생존 → GUI 정상 실행 중 → 이후 종료 시 stderr 재확인.
        """
        CRASH_DETECT_TIMEOUT = 5

        # stderr를 별도 스레드로 실시간 수집 (readline 블로킹 방지)
        stderr_lines = []

        def _read_stderr():
            try:
                for line in proc.stderr:
                    stderr_lines.append(line)
            except Exception:
                pass

        stderr_thread = threading.Thread(target=_read_stderr, daemon=True)
        stderr_thread.start()

        # [Fix 2026-04-26 D] stderr 마지막 'Error:' 라인 추출 + 진단 로그 강화.
        # 1) child 가 빨리 죽으면 stderr 가 부분만 캡처될 수 있음 → 최종 drain.
        # 2) 진단 print 가 [:200] 으로 잘려 traceback 끝 (TypeError ...) 가 안 보였음
        #    → 마지막 Error 라인 우선 노출.
        def _final_drain():
            try:
                # iterator 가 닫힐 때까지 대기. closed 면 read() 빈 문자열 반환.
                _rest = proc.stderr.read() if proc.stderr else ""
                if _rest:
                    stderr_lines.append(_rest)
            except Exception:
                pass

        def _last_error_line(text: str) -> str:
            """traceback 의 마지막 'Error: ...' / 'Exception: ...' 라인 반환."""
            for _l in reversed(text.splitlines()):
                _ls = _l.strip()
                if _ls and ("Error" in _ls or "Exception" in _ls) and ":" in _ls:
                    return _ls
            return ""

        try:
            proc.wait(timeout=CRASH_DETECT_TIMEOUT)
            # 5초 안에 종료 → 크래시
            stderr_thread.join(timeout=3)
            _final_drain()
            returncode = proc.returncode
            combined = "".join(stderr_lines).strip()

            if not combined:
                combined = f"앱이 즉시 종료되었습니다 (returncode={returncode}).\nimport 오류 또는 초기화 실패 가능성.\n진입점: {self._entry_path}"
            else:
                # traceback 전체 보존 — 4000자까지 확장 (P2 시그니처 정규식 매칭 보장)
                combined = combined[-4000:]

            err_captured = combined
            _last_err = _last_error_line(err_captured)
            print(
                f"[ScaffoldCard] 크래시 감지 (rc={returncode}, len={len(err_captured)}): "
                f"{err_captured[:200]}"
            )
            if _last_err:
                print(f"[ScaffoldCard]   ↳ 마지막 에러 라인: {_last_err[:300]}")
            QTimer.singleShot(0, lambda: self._show_error(err_captured))
            # Signal emit은 스레드 안전 — GUI 스레드에서 _send_error_to_eidos 실행
            self._crash_detected.emit(err_captured)

        except subprocess.TimeoutExpired:
            # 5초 생존 → 정상 실행 중
            try:
                proc.wait(timeout=600)
                stderr_thread.join(timeout=3)
                _final_drain()
                returncode = proc.returncode
                combined = "".join(stderr_lines).strip()
                if returncode != 0 and combined:
                    err_msg = combined[-4000:]
                    _last_err = _last_error_line(err_msg)
                    print(
                        f"[ScaffoldCard] 런타임 오류 (rc={returncode}, len={len(err_msg)}): "
                        f"{err_msg[:200]}"
                    )
                    if _last_err:
                        print(f"[ScaffoldCard]   ↳ 마지막 에러 라인: {_last_err[:300]}")
                    QTimer.singleShot(0, lambda: self._show_error(err_msg))
                    self._crash_detected.emit(err_msg)
            except Exception:
                pass
        except Exception as e:
            print(f"[ScaffoldCard] _monitor_proc 예외: {e}")

    # 하위 호환 alias
    def _monitor_stderr(self, proc: subprocess.Popen):
        self._monitor_proc(proc)

    def _show_error(self, msg: str):
        self._error_lbl.setText(f"❌ 실행 오류:\n{msg}")
        self._error_lbl.setVisible(True)
        self._run_btn.setEnabled(True)
        self._run_btn.setText(f"▶  재실행   ({os.path.basename(self._entry_path)})")
        # 오류가 보이도록 스크롤
        if self._chat and hasattr(self._chat, "chat_scroll_area"):
            QTimer.singleShot(50, lambda: (
                self._chat.chat_scroll_area.ensureWidgetVisible(self._error_lbl)
                if self._error_lbl.isVisible() else None
            ))

    def _send_error_to_eidos(self, error_text: str):
        """오류 감지 → fix_and_rerun_async로 자동 수정 루프 시작."""
        # ── 인스턴스 레벨 카운터로 무한루프 원천 차단 ──────────────────────
        # fix_and_rerun 내부 seen_errors는 같은 태스크 내에서만 유효.
        # 크래시→감지→재실행→크래시 사이클에서 매번 새 태스크가 생성되므로
        # 인스턴스 레벨에서 총 호출 횟수를 제한해야 함.
        self._autofix_count += 1
        if self._autofix_count > self._AUTOFIX_MAX:
            print(f"[ScaffoldCard] 자동 수정 한도 초과 ({self._AUTOFIX_MAX}회) — 루프 강제 중단")
            if self._chat:
                self._chat.append_message(
                    f"⛔ 자동 수정 {self._AUTOFIX_MAX}회 한도 초과 — 수동으로 오류를 확인하세요.",
                    "system"
                )
            return

        if not self._chat or not self._worker:
            print("[ScaffoldCard] _send_error_to_eidos: _chat 또는 _worker 없음 — 루프 불가")
            return

        proj_dir = self._result.get("project_dir", "project")
        files    = self._result.get("files", {})

        self._chat.append_message(
            f"🤖 실행 오류 감지 — 자동 수정 시도 ({self._autofix_count}/{self._AUTOFIX_MAX})", "system"
        )

        # 현재 파일 내용을 디스크에서 읽어서 전달
        # .py 파일만 필터링 — .js/.jsx/.ts 등 비파이썬 파일은 수정 대상 아님
        from execution_module import SAFE_BASE_PATH
        current_files = {}
        for rel in files.keys():
            if not rel.endswith(".py"):
                continue  # 비파이썬 파일 제외
            abs_path = os.path.join(SAFE_BASE_PATH, "projects", proj_dir, rel)
            try:
                with open(abs_path, "r", encoding="utf-8") as f:
                    current_files[rel] = f.read()
            except Exception:
                current_files[rel] = files.get(rel, "")

        if not current_files:
            print("[ScaffoldCard] _send_error_to_eidos: current_files 비어있음 — 루프 불가")
            return

        print(f"[ScaffoldCard] fix_and_rerun_async 시작: proj={proj_dir}, files={list(current_files.keys())[:3]}")
        self._worker.submit_task(
            self._worker.fix_and_rerun_async(
                error_text  = error_text,
                project_dir = proj_dir,
                base_dir    = self._base_dir,
                files       = current_files,
                max_retries = 1,  # 태스크당 1회 — 외부 카운터가 총 횟수 관리
            )
        )

# ─────────────────────────────────────────────────────────────────────────────

def _load_checklist_templates() -> list:
    """\uccb4\ud06c\ub9ac\uc2a4\ud2b8 \ud15c\ud50c\ub9bf \ubaa9\ub85d \ub85c\ub4dc. \ud30c\uc77c \uc5c6\uac70\ub098 \uae68\uc84c\uc73c\uba74 \ube48 \ub9ac\uc2a4\ud2b8."""
    try:
        if not os.path.exists(CHECKLIST_TEMPLATES_FILE):
            return []
        with open(CHECKLIST_TEMPLATES_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
        items = data.get("templates", []) if isinstance(data, dict) else []
        return [t for t in items if isinstance(t, dict) and t.get("name")]
    except Exception as _e:
        print(f"[ChecklistTemplate] \ub85c\ub4dc \uc2e4\ud328: {_e}")
        return []


def _save_checklist_templates(templates: list) -> bool:
    try:
        _dir = os.path.dirname(CHECKLIST_TEMPLATES_FILE)
        if _dir:
            os.makedirs(_dir, exist_ok=True)
        with open(CHECKLIST_TEMPLATES_FILE, "w", encoding="utf-8") as f:
            json.dump({"templates": templates}, f, ensure_ascii=False, indent=2)
        return True
    except Exception as _e:
        print(f"[ChecklistTemplate] \uc800\uc7a5 \uc2e4\ud328: {_e}")
        return False


